// ── PRODUCT DEVELOPMENT ──
let allPDRows = [];
let pdAllVendors = [];
let pdAllCollections = [];
let pdCollItemsByCol = {};
let pdCollItemCounts = {};   // {collection_id: number_of_requested_sku_parents}
let pdSearchQuery = '';
let pdFilters = {vendor:'',type:''};
let pdPicsToUpload = [];
let _pdSearchTimer = null;
let pdCurrentCollectionId = '';
let pdEditingId = '';   // ID of the parent or variant currently being inline-edited
const PD_BUCKET = 'product-dev-pictures';
const PD_MAX_PICS = 2;

function mapPD(r) {
  return {
    id: r.id, parentId: r.parent_id, collectionId: r.collection_id,
    collectionItemId: r.collection_item_id, skuName: r.sku_name||'',
    displayCode: r.display_code||'', skuType: r.sku_type||null,
    variant: r.variant||'', size: r.size||'', color: r.color||'',
    vendor: r.vendor||'', hpp: r.hpp, qty: r.qty, srp: r.srp,
    pictures: r.picture_urls||[], notes: r.notes||'',
    dateAdded: r.date_added, addedBy: r.added_by,
    lastUpdated: r.last_updated, lastUpdatedBy: r.last_updated_by
  };
}

// Build the variant token used inside the SKU code: SIZE[-COLOR][-OTHER]
function pdVariantTokenFor(size, color, other) {
  const parts = [];
  if (size)  parts.push(pdVariantToken(size));
  if (color) parts.push(pdVariantToken(color));
  if (other) parts.push(pdVariantToken(other));
  return parts.join('-') || 'OS';
}

// Pretty display string for a variant SKU
function pdVariantDisplay(v) {
  const parts = [];
  if (v.size)  parts.push(v.size);
  if (v.color) parts.push(v.color);
  if (v.variant) parts.push(v.variant);
  return parts.join(' / ');
}

function pdCollName(id) {
  return (pdAllCollections.find(c=>c.id===id)?.collection_name) || '—';
}

function pdCollIP(id) {
  return (pdAllCollections.find(c=>c.id===id)?.ip_related) || '';
}

// Take first 3 alphanumeric chars, uppercase, pad with X if shorter
function pdShort3(s) {
  const t = (s||'').replace(/[^a-zA-Z0-9]/g,'').toUpperCase();
  return (t.slice(0,3) || 'XXX').padEnd(3,'X');
}

function pdVariantToken(v) {
  const t = (v||'').replace(/[^a-zA-Z0-9]/g,'').toUpperCase();
  return t || 'OS';
}

// Parent product code: {IP3}-{COL3}-{NN}
// NN sequence is per-collection across parent rows only.
function generateNextParentCode(collection_id) {
  const ip  = pdShort3(pdCollIP(collection_id));
  const col = pdShort3(pdCollName(collection_id));
  const prefix = `${ip}-${col}-`;
  // Only count parent rows so parent and variant codes don't collide.
  // Parent codes have no variant segment, so they look like IP-COL-NN.
  const parentRe = new RegExp(`^${ip.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')}-${col.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')}-([0-9]{2,})$`);
  const taken = new Set();
  allPDRows.filter(r => r.collectionId === collection_id && !r.parentId).forEach(r => {
    if (r.displayCode && parentRe.test(r.displayCode)) taken.add(r.displayCode);
  });
  for (let i = 1; i <= 999; i++) {
    const code = `${prefix}${String(i).padStart(2,'0')}`;
    if (!taken.has(code)) return code;
  }
  return `${prefix}${Date.now()%1000}`;
}

// Classify a child row as either 'variant' (size/color SKU of the same product)
// or 'bundle_item' (a different product included in a bundle).
// Uses explicit sku_type when set; falls back to size/color presence for legacy rows.
function pdChildKind(c) {
  if (c.skuType === 'variant' || c.skuType === 'bundle_item') return c.skuType;
  if (c.size || c.color) return 'variant';
  return 'bundle_item';
}
function pdVariantsOf(parentId) {
  return allPDRows.filter(r => r.parentId === parentId && pdChildKind(r) === 'variant');
}
function pdBundleItemsOf(parentId) {
  return allPDRows.filter(r => r.parentId === parentId && pdChildKind(r) === 'bundle_item');
}

// Bundle item code: {PARENT_CODE}.A, .B, .C ...
// Different from variant codes — bundle items are flat letter sequences under their parent.
function generateNextBundleCode(parent_id) {
  const parent = allPDRows.find(r => r.id === parent_id);
  if (!parent) return '';
  const parentCode = parent.displayCode || parent.id;
  const taken = new Set(allPDRows
    .filter(r => r.parentId === parent_id && r.displayCode && r.displayCode.startsWith(parentCode + '.'))
    .map(r => r.displayCode));
  const letter = i => {
    let s = '';
    do { s = String.fromCharCode(65 + (i % 26)) + s; i = Math.floor(i/26) - 1; } while (i >= 0);
    return s;
  };
  for (let i = 0; i < 700; i++) {
    const code = `${parentCode}.${letter(i)}`;
    if (!taken.has(code)) return code;
  }
  return `${parentCode}.X${Date.now()%100}`;
}

// Variant code: {IP3}-{COL3}-{SIZE}-{NN}
// Sequence is per (collection, size) across variant rows.
function generateNextVariantCode(collection_id, size) {
  const ip  = pdShort3(pdCollIP(collection_id));
  const col = pdShort3(pdCollName(collection_id));
  const vrt = pdVariantToken(size);
  const prefix = `${ip}-${col}-${vrt}-`;
  const taken = new Set(allPDRows
    .filter(r => r.collectionId === collection_id && r.parentId && r.displayCode && r.displayCode.startsWith(prefix))
    .map(r => r.displayCode));
  for (let i = 1; i <= 999; i++) {
    const code = `${prefix}${String(i).padStart(2,'0')}`;
    if (!taken.has(code)) return code;
  }
  return `${prefix}${Date.now()%1000}`;
}

// Standard size options for the variant form
const PD_SIZE_OPTIONS = ['S','M','L','XL','XXL','XXXL'];

function updatePDCodePreview() {
  const el = document.getElementById('pd-code-preview');
  if (!el) return;
  if (!pdCurrentCollectionId) { el.textContent = '—'; return; }
  el.textContent = generateNextParentCode(pdCurrentCollectionId);
}

function pdFmtIDR(n) {
  if (n===null||n===undefined||n==='') return '—';
  return new Intl.NumberFormat('id-ID').format(Number(n));
}

// Projection: how much was produced, capital, expected revenue, margin.
// Returns null/zero fields when inputs are missing.
//
// Units-produced semantics:
//   - variants present  → Σ variant.qty (each variant qty = stock count of that size)
//   - pure bundle       → min(bundle_item.qty) — each bundle needs 1 of each component,
//                         so the limiting component caps how many bundles can be made.
//                         Components above this count are "leftover" but their cost is
//                         still in modal.
//   - mixed             → variants drive units; bundle item cost is added on top.
function pdComputeProjection(parent, allChildren) {
  allChildren = allChildren || [];
  const variants    = allChildren.filter(c => pdChildKind(c) === 'variant');
  const bundleItems = allChildren.filter(c => pdChildKind(c) === 'bundle_item');

  let units = 0;
  if (variants.length) {
    units = variants.reduce((s,v)=>s+Number(v.qty||0), 0);
  } else if (bundleItems.length) {
    const qtys = bundleItems.map(b => Number(b.qty||0)).filter(q => q > 0);
    units = qtys.length ? Math.min(...qtys) : 0;
  }

  // Modal (total capital outlay): Σ child.hpp × child.qty across ALL children
  const modal = allChildren.reduce((s,c)=>s + (Number(c.hpp||0) * Number(c.qty||0)), 0);

  // Per-unit cost
  const unitCost = units ? modal / units : null;

  const srp = Number(parent.srp||0);
  const revenue100 = (srp && units) ? srp * units : 0;
  const grossMargin    = revenue100 - modal;
  const grossMarginPct = revenue100 ? (grossMargin / revenue100) * 100 : null;

  // Ratio = SRP per item / cost per item. This is the per-unit markup.
  const ratio = (srp && unitCost) ? srp / unitCost : null;

  return { units, modal, unitCost, revenue100, grossMargin, grossMarginPct, ratio };
}

// Global projection: sum across all products in the current collection.
function pdComputeGlobalProjection() {
  const cid = pdCurrentCollectionId;
  const parents = allPDRows.filter(r => !r.parentId && r.collectionId === cid);
  let units = 0, modal = 0, revenue100 = 0;
  parents.forEach(p => {
    const children = allPDRows.filter(r => r.parentId === p.id);
    const proj = pdComputeProjection(p, children);
    units      += proj.units || 0;
    modal      += proj.modal || 0;
    revenue100 += proj.revenue100 || 0;
  });
  const grossMargin    = revenue100 - modal;
  const grossMarginPct = revenue100 ? (grossMargin / revenue100) * 100 : null;
  return { units, modal, revenue100, grossMargin, grossMarginPct, productCount: parents.length };
}

// Back-compat: existing call sites use pdComputeRatio(parent, subs).
function pdComputeRatio(parent, subs) {
  return pdComputeProjection(parent, subs).ratio;
}

async function loadPDVendorList() {
  try {
    const [{data:poData},{data:pdData}] = await Promise.all([
      sb.from('jubelio_purchase_orders').select('supplier_name').not('supplier_name','is',null).limit(5000),
      sb.from('product_dev').select('vendor').not('vendor','is',null).limit(5000)
    ]);
    const set = new Set();
    (poData||[]).forEach(r => { if (r.supplier_name) set.add(r.supplier_name.trim()); });
    (pdData||[]).forEach(r => { if (r.vendor) set.add(r.vendor.trim()); });
    pdAllVendors = [...set].filter(Boolean).sort();
  } catch(e) { console.error('loadPDVendorList:',e); pdAllVendors=[]; }
}

async function loadPDCollections() {
  const {data} = await sb.from('collections').select('id,collection_name,ip_related,release_date,revenue_stream,pd_active').order('collection_name');
  pdAllCollections = data || [];
  // Count requested SKU parents per collection (from Collection Development).
  // Used to compute X/Y "request fulfillment" progress on the grid cards.
  try {
    const {data: itemData} = await sb.from('collection_items').select('id,collection_id').limit(20000);
    pdCollItemCounts = {};
    (itemData||[]).forEach(it => {
      if (!it.collection_id) return;
      pdCollItemCounts[it.collection_id] = (pdCollItemCounts[it.collection_id]||0) + 1;
    });
  } catch(e) { console.error('loadPDCollections counts:', e); pdCollItemCounts = {}; }
}

async function loadPDCollectionItems(collectionId) {
  if (!collectionId) return [];
  if (pdCollItemsByCol[collectionId]) return pdCollItemsByCol[collectionId];
  const {data} = await sb.from('collection_items').select('id,sku_name').eq('collection_id',collectionId).order('sku_name');
  pdCollItemsByCol[collectionId] = data || [];
  return pdCollItemsByCol[collectionId];
}

// ── Routing entry point ────────────────────────────────────────────
async function loadProductDev() {
  // Always pull latest data so stats stay in sync across views
  await Promise.all([loadPDCollections(), loadPDVendorList(), fetchPDRows()]);

  // Route based on hash: #productdev → grid, #productdev/{id} → detail
  const hash = location.hash.slice(1);
  const m = hash.match(/^productdev\/(.+)$/);
  if (m) {
    pdCurrentCollectionId = decodeURIComponent(m[1]);
    showPDDetailView();
  } else {
    pdCurrentCollectionId = '';
    showPDGridView();
  }
}

async function fetchPDRows() {
  try {
    const {data, error} = await sb.from('product_dev').select('*').order('display_code',{ascending:true}).limit(5000);
    if (error) throw error;
    allPDRows = (data||[]).map(mapPD);
  } catch(e) { console.error('fetchPDRows:',e); allPDRows=[]; }
}

function showPDGridView() {
  document.getElementById('pd-view-grid').style.display = '';
  document.getElementById('pd-view-detail').style.display = 'none';
  renderPDGrid();
}

function showPDDetailView() {
  document.getElementById('pd-view-grid').style.display = 'none';
  document.getElementById('pd-view-detail').style.display = '';
  renderPDDetail();
}

function openPDGrid() {
  pdCurrentCollectionId = '';
  history.replaceState(null,'','#productdev');
  showPDGridView();
}

function openPDDetail(collection_id) {
  pdCurrentCollectionId = collection_id;
  history.replaceState(null,'',`#productdev/${encodeURIComponent(collection_id)}`);
  showPDDetailView();
}

// ── GRID VIEW ──────────────────────────────────────────────────────
// Days from today until the given date (YYYY-MM-DD or ISO).
// Returns positive for future, 0 for today, negative for past, null when missing.
function pdDaysUntil(dateStr) {
  if (!dateStr) return null;
  const target = new Date(dateStr);
  if (isNaN(target)) return null;
  const today = new Date();
  // Normalize to local midnight for both
  target.setHours(0,0,0,0); today.setHours(0,0,0,0);
  return Math.round((target - today) / 86400000);
}

function pdFmtLaunchDate(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  if (isNaN(d)) return '';
  return d.toLocaleDateString('id-ID', {day:'2-digit',month:'short',year:'numeric'});
}

// Brand color for the revenue-stream chip: SD&Y = black, Lagaa = maroon, Marte = yellow.
function pdRevChipStyle(rev) {
  // Substring match on lowercased value (tolerant of accents like "marté", and "SD&Y" vs "SDY")
  const r = (rev||'').toLowerCase();
  if (r.includes('lagaa'))                 return {bg:'#6d1f2b', fg:'#ffffff', border:'#6d1f2b'};  // merah maroon
  if (r.includes('sd'))                    return {bg:'#0c0c0c', fg:'#ffffff', border:'#0c0c0c'};  // item (hitam)
  if (r.includes('mart'))                  return {bg:'#f5c518', fg:'#3a2e00', border:'#e0b400'};  // kuning
  return {bg:'var(--off)', fg:'var(--g600)', border:'var(--g100)'};                                // lainnya
}

// Color tone based on days remaining
function pdLaunchTone(days) {
  if (days === null)        return {bg:'#e8e8e3', fg:'#666',    border:'#d6d5cc', label:'No launch date'};
  if (days < 0)             return {bg:'#eef1ee', fg:'#6c7c6f', border:'#c8d2c8', label:`Launched ${-days}d ago`};
  if (days === 0)           return {bg:'#fde0e0', fg:'#b81d1d', border:'#f3a8a8', label:'Launches today!'};
  if (days <= 7)            return {bg:'#fde0e0', fg:'#b81d1d', border:'#f3a8a8', label:`${days}d to launch`};
  if (days <= 30)           return {bg:'#fef0d0', fg:'#a66800', border:'#f1cf7a', label:`${days}d to launch`};
  return                            {bg:'#daf3e0', fg:'#0a7d3a', border:'#a7dab4', label:`${days}d to launch`};
}

function renderPDGrid() {
  // Populate IP filter dropdown so new IPs are picked up across reloads.
  const ipSel = document.getElementById('pd-grid-ip');
  if (ipSel) {
    const ips = [...new Set(pdAllCollections.map(c => (c.ip_related||'').trim()).filter(Boolean))].sort();
    const cur = ipSel.value;
    ipSel.innerHTML = `<option value="">Semua IP / Artist</option>` +
      ips.map(ip => `<option value="${ip.replace(/"/g,'&quot;')}"${ip===cur?' selected':''}>${ip.replace(/</g,'&lt;')}</option>`).join('');
  }

  // Populate revenue-stream filter dropdown
  const revSel = document.getElementById('pd-grid-rev');
  if (revSel) {
    const revs = [...new Set(pdAllCollections.map(c => (c.revenue_stream||'').trim()).filter(Boolean))].sort();
    const cur = revSel.value;
    revSel.innerHTML = `<option value="">Semua Revenue Stream</option>` +
      revs.map(r => `<option value="${r.replace(/"/g,'&quot;')}"${r===cur?' selected':''}>${r.replace(/</g,'&lt;')}</option>`).join('');
  }

  const search    = (document.getElementById('pd-grid-search')?.value || '').trim().toLowerCase();
  const ipFilter  = (ipSel?.value || '').trim();
  const revFilter = (revSel?.value || '').trim();

  // Apply filters to the collections grid
  const cols = pdAllCollections.filter(c => {
    if (ipFilter && (c.ip_related||'').toLowerCase() !== ipFilter.toLowerCase()) return false;
    if (revFilter && (c.revenue_stream||'').toLowerCase() !== revFilter.toLowerCase()) return false;
    if (search && !(c.collection_name||'').toLowerCase().includes(search)) return false;
    return true;
  });
  // Inactive collections always sink to the bottom. Within each active/inactive
  // bucket, sort by closest launch first: upcoming ascending, then past, then no-date.
  cols.sort((a, b) => {
    const aActive = a.pd_active !== false, bActive = b.pd_active !== false;
    if (aActive !== bActive) return aActive ? -1 : 1;        // active first, inactive last
    const da = pdDaysUntil(a.release_date);
    const db = pdDaysUntil(b.release_date);
    const rank = d => d === null ? 3 : d < 0 ? 2 : 1;       // upcoming → 1, past → 2, none → 3
    const ra = rank(da), rb = rank(db);
    if (ra !== rb) return ra - rb;
    if (ra === 1) return da - db;                            // both upcoming → soonest first
    if (ra === 2) return db - da;                            // both past → most recent first (least negative wins)
    return (a.collection_name||'').localeCompare(b.collection_name||'');
  });
  document.getElementById('pd-grid-tcount').textContent = `${cols.length} collection`;

  const grid = document.getElementById('pd-grid');
  if (!grid) return;

  if (!cols.length) {
    grid.innerHTML = `<div class="empty-td" style="grid-column:1/-1">${pdAllCollections.length ? 'Tidak ada collection cocok filter.' : 'Belum ada collection. Buat collection dulu di Collection Development.'}</div>`;
    return;
  }

  // Color thresholds for request fulfillment urgency.
  // requested === 0      → gray "no requests"
  // 100% mapped          → green
  // ≥50% mapped          → orange
  // <50% mapped          → red
  const urgencyTone = (mapped, requested) => {
    if (!requested)                return {bg:'#e8e8e3', fg:'#666',     border:'#d6d5cc'};
    if (mapped >= requested)       return {bg:'#daf3e0', fg:'#0a7d3a',  border:'#a7dab4'};
    if (mapped / requested >= 0.5) return {bg:'#fef0d0', fg:'#a66800',  border:'#f1cf7a'};
    return                                {bg:'#fde0e0', fg:'#b81d1d',  border:'#f3a8a8'};
  };

  grid.innerHTML = cols.map(c => {
    const requested = pdCollItemCounts[c.id] || 0;
    const mapped = new Set(
      allPDRows
        .filter(r => !r.parentId && r.collectionId === c.id && r.collectionItemId)
        .map(r => r.collectionItemId)
    ).size;
    const tone = urgencyTone(mapped, requested);
    const pct = requested ? Math.round((mapped/requested)*100) : 0;
    const progressLabel = requested
      ? `${mapped}/${requested} SKU mapped${requested>0?` · ${pct}%`:''}`
      : `No requests dari brand`;

    const name = (c.collection_name||c.id).replace(/</g,'&lt;');
    const ip   = (c.ip_related||'').trim();
    const rev  = (c.revenue_stream||'').trim();
    const active = c.pd_active !== false;

    // Launch urgency
    const days = pdDaysUntil(c.release_date);
    const launchTone = pdLaunchTone(days);
    const launchDate = pdFmtLaunchDate(c.release_date);

    // Progress bar always present so every card has the same height.
    const barFill = requested ? Math.min(100, pct) : 0;
    const barColor = requested ? tone.fg : 'var(--g100)';
    const progressBar = `<div style="height:4px;background:var(--g100);border-radius:2px;overflow:hidden">
      <div style="height:100%;width:${barFill}%;background:${barColor};transition:width 0.2s"></div>
    </div>`;

    // Revenue-stream chip (top-right) + active/inactive toggle
    const revStyle = pdRevChipStyle(rev);
    const revChip = rev
      ? `<span style="font-size:9px;font-weight:700;font-family:var(--mono);padding:2px 8px;border-radius:99px;background:${revStyle.bg};color:${revStyle.fg};border:1px solid ${revStyle.border};white-space:nowrap">${rev.replace(/</g,'&lt;')}</span>`
      : '';
    const toggle = `<button onclick="event.stopPropagation();togglePDActive('${c.id}',${active?'false':'true'})"
      title="${active?'Tandai inactive':'Tandai active'}"
      style="font-size:9px;font-weight:600;font-family:var(--mono);padding:2px 8px;border-radius:99px;cursor:pointer;white-space:nowrap;border:1px solid ${active?'#a7dab4':'#e0a8a8'};background:${active?'#daf3e0':'#fbe6e6'};color:${active?'#0a7d3a':'#b81d1d'}">${active?'● Active':'○ Inactive'}</button>`;

    return `<div class="tool-card" onclick="openPDDetail('${c.id}')" style="cursor:pointer;padding:14px 16px;display:flex;flex-direction:column;gap:10px;height:100%;box-sizing:border-box;${active?'':'opacity:0.55'}">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">
        <div style="min-width:0">
          ${ip
            ? `<div style="font-size:14px;font-weight:700;color:var(--black);font-family:var(--syne,var(--sans));letter-spacing:0.3px">${ip.replace(/</g,'&lt;')}</div>`
            : `<div style="font-size:11px;color:var(--g400);font-style:italic">No IP set</div>`}
          <div style="font-size:12px;color:var(--g600);margin-top:2px">${name}</div>
        </div>
        ${revChip}
      </div>
      <div style="display:flex;flex-direction:column;align-items:stretch;gap:6px;margin-top:auto">
        <span style="display:block;text-align:center;font-size:11px;font-weight:600;padding:5px 10px;border-radius:4px;font-family:var(--mono);background:${tone.bg};color:${tone.fg};border:1px solid ${tone.border};box-sizing:border-box;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${progressLabel}</span>
        <span style="display:flex;flex-direction:column;align-items:center;gap:1px;line-height:1.25;font-size:11px;font-weight:600;padding:5px 10px;border-radius:4px;font-family:var(--mono);background:${launchTone.bg};color:${launchTone.fg};border:1px solid ${launchTone.border};box-sizing:border-box">
          <span>📅 ${launchTone.label}</span>${launchDate?`<span style="font-weight:500;opacity:0.85">${launchDate}</span>`:''}
        </span>
        <div style="display:flex;justify-content:center">${toggle}</div>
      </div>
      ${progressBar}
    </div>`;
  }).join('');
}

// Toggle a collection's active state in the Product Dev grid.
// Inactive collections sink to the bottom of the grid (see sort in renderPDGrid).
async function togglePDActive(collectionId, newActive) {
  const active = newActive === true || newActive === 'true';
  // optimistic local update
  const c = pdAllCollections.find(x => x.id === collectionId);
  if (c) c.pd_active = active;
  renderPDGrid();
  try {
    const {error} = await sb.from('collections').update({pd_active: active}).eq('id', collectionId);
    if (error) throw error;
  } catch(e) {
    console.error('togglePDActive:', e);
    if (c) c.pd_active = !active;   // revert on failure
    renderPDGrid();
    alert('Gagal mengubah status: ' + (e.message||e));
  }
}

// ── DETAIL VIEW ────────────────────────────────────────────────────
function renderPDDetail() {
  const cid = pdCurrentCollectionId;
  const coll = pdAllCollections.find(c=>c.id===cid);
  if (!coll) {
    document.getElementById('pd-d-title').textContent = 'Collection tidak ditemukan';
    document.getElementById('pd-d-sub').textContent = '';
    document.getElementById('pdTableBody').innerHTML = `<tr><td class="empty-td" colspan="10">Collection ID tidak valid. <a href="#productdev" onclick="openPDGrid();return false">Kembali</a></td></tr>`;
    return;
  }
  document.getElementById('pd-d-title').textContent = coll.collection_name || cid;
  const ip3 = pdShort3(coll.ip_related);
  const col3 = pdShort3(coll.collection_name);
  document.getElementById('pd-d-sub').textContent = `Product Development · code prefix: ${ip3}-${col3}-{VARIANT}-NN${coll.ip_related?'':' (IP belum di-set di Collection)'}`;

  // Populate form helpers tied to this collection
  populatePDDetailForm();
  setupPDPicInput();
  onPDTypeChange(); // ensure solo fields visible
  updatePDCodePreview();
  // Populate SKU name autocomplete
  loadPDCollectionItems(cid).then(items => {
    const dl = document.getElementById('pd-sku-datalist');
    if (dl) dl.innerHTML = items.map(it => `<option value="${(it.sku_name||'').replace(/"/g,'&quot;')}" data-id="${it.id}">`).join('');
  });

  renderPDDetailTable();
}

function populatePDDetailForm() {
  // Vendor filter dropdown + datalist
  const vSel = document.getElementById('pd-fil-vendor');
  if (vSel) {
    const cur = vSel.value;
    vSel.innerHTML = `<option value="">Semua Vendor</option>` +
      pdAllVendors.map(v => `<option value="${v.replace(/"/g,'&quot;')}">${v.replace(/</g,'&lt;')}</option>`).join('');
    if (cur) vSel.value = cur;
  }
  const vDl = document.getElementById('pd-vendor-datalist');
  if (vDl) vDl.innerHTML = pdAllVendors.map(v=>`<option value="${v.replace(/"/g,'&quot;')}">`).join('');
}

function onPDTypeChange() {
  // No-op now that the Solo/Multi radio is gone. Kept as a safe stub
  // in case any older inline handler still references it.
}

function togglePDAddForm() {
  const body = document.getElementById('pd-add-body');
  const caret = document.getElementById('pd-add-caret');
  if (!body) return;
  if (body.style.display === 'none') { body.style.display = ''; caret.textContent = '▼'; }
  else { body.style.display = 'none'; caret.textContent = '▶'; }
}

function setupPDPicInput() {
  const inp = document.getElementById('pd-pics');
  if (!inp || inp._pdWired) return;
  inp._pdWired = true;
  inp.addEventListener('change', e => {
    const files = [...e.target.files];
    if (files.length > PD_MAX_PICS) alert(`Maks ${PD_MAX_PICS} foto. Hanya ${PD_MAX_PICS} pertama dipakai.`);
    pdPicsToUpload = files.slice(0, PD_MAX_PICS);
    const prev = document.getElementById('pd-pics-preview');
    prev.innerHTML = pdPicsToUpload.map(f=>`<span style="font-size:11px;padding:3px 8px;background:var(--off);border-radius:4px">📎 ${f.name}</span>`).join('');
  });
}

function onPDSearch(val) {
  clearTimeout(_pdSearchTimer);
  _pdSearchTimer = setTimeout(()=>{ pdSearchQuery = val.trim(); renderPDDetailTable(); }, 250);
}

function clearPDFilters() {
  pdFilters = {vendor:'',type:''};
  pdSearchQuery = '';
  ['pd-fil-vendor','pd-fil-type','pd-search'].forEach(id=>{
    const el = document.getElementById(id); if (el) el.value='';
  });
  renderPDDetailTable();
}

function clearPDForm() {
  ['pd-sku-name','pd-srp','pd-notes'].forEach(id=>{
    const el = document.getElementById(id); if (el) el.value='';
  });
  const pics = document.getElementById('pd-pics');
  if (pics) pics.value = '';
  const prev = document.getElementById('pd-pics-preview');
  if (prev) prev.innerHTML = '';
  pdPicsToUpload = [];
  const fb = document.getElementById('pd-feedback');
  if (fb) fb.textContent = '';
  updatePDCodePreview();
}

// ── Picture handling: bulletproof file-picker ──────────────────────
function pickPicForRecord(recordId) {
  const row = allPDRows.find(r=>r.id===recordId);
  if (!row) return;
  if ((row.pictures||[]).length >= PD_MAX_PICS) {
    alert(`Maks ${PD_MAX_PICS} foto per SKU. Hapus salah satu dulu.`); return;
  }
  const inp = document.createElement('input');
  inp.type = 'file';
  inp.accept = 'image/*';
  inp.style.display = 'none';
  inp.onchange = e => {
    const f = e.target.files[0];
    if (f) addPDPicture(recordId, f);
    document.body.removeChild(inp);
  };
  document.body.appendChild(inp);
  inp.click();
}

async function uploadPDPicture(file, sku_id) {
  const ext = (file.name.split('.').pop()||'jpg').toLowerCase();
  const path = `${sku_id}/${Date.now()}-${Math.floor(Math.random()*1000)}.${ext}`;
  const {error} = await sb.storage.from(PD_BUCKET).upload(path, file, {contentType: file.type, upsert: false});
  if (error) throw error;
  const {data:{publicUrl}} = sb.storage.from(PD_BUCKET).getPublicUrl(path);
  return publicUrl;
}

async function addPDPicture(id, file) {
  const row = allPDRows.find(r=>r.id===id);
  if (!row) return;
  if ((row.pictures||[]).length >= PD_MAX_PICS) { alert(`Maks ${PD_MAX_PICS} foto.`); return; }
  try {
    const url = await uploadPDPicture(file, id);
    const newPics = [...(row.pictures||[]), url];
    const {error} = await sb.from('product_dev').update({
      picture_urls:newPics, last_updated:new Date().toISOString(), last_updated_by:currentUser
    }).eq('id',id);
    if (error) throw error;
    row.pictures = newPics;
    renderPDDetailTable();
  } catch(e) { alert('Upload gagal: '+(e.message||e)); }
}

async function removePDPicture(id, url) {
  if (!confirm('Hapus foto ini?')) return;
  const marker = `/${PD_BUCKET}/`;
  const idx = url.indexOf(marker);
  if (idx >= 0) {
    const path = url.slice(idx + marker.length);
    await sb.storage.from(PD_BUCKET).remove([path]);
  }
  const row = allPDRows.find(r=>r.id===id);
  if (!row) return;
  const newPics = (row.pictures||[]).filter(u=>u!==url);
  const {error} = await sb.from('product_dev').update({
    picture_urls:newPics, last_updated:new Date().toISOString(), last_updated_by:currentUser
  }).eq('id',id);
  if (error) { alert('Gagal hapus: '+error.message); return; }
  row.pictures = newPics;
  renderPDDetailTable();
}

// ── Submit parent SKU ──────────────────────────────────────────────
async function submitPD() {
  const fb = document.getElementById('pd-feedback');
  const btn = document.getElementById('pdSubmitBtn');
  const cid = pdCurrentCollectionId;
  if (!cid) { fb.textContent='⚠️ Buka detail collection dulu.'; return; }
  const skuName = document.getElementById('pd-sku-name').value.trim();
  const srp = parseFloat(document.getElementById('pd-srp').value);
  const notes = document.getElementById('pd-notes').value.trim();

  if (!skuName) { fb.textContent='⚠️ Nama produk wajib.'; return; }

  // Auto-generate parent product code: {IP}-{COL}-{NN}
  const displayCode = generateNextParentCode(cid);

  // Resolve collection_item_id from chosen SKU name (if match)
  let collItemId = null;
  const items = await loadPDCollectionItems(cid);
  const match = items.find(it => (it.sku_name||'').trim().toLowerCase() === skuName.toLowerCase());
  if (match) collItemId = match.id;

  btn.disabled = true; fb.textContent = 'Menyimpan...';
  try {
    const id = genId('PD');
    const payload = {
      id, parent_id: null, collection_id: cid, collection_item_id: collItemId,
      display_code: displayCode, sku_type: 'product',
      sku_name: skuName,
      srp: isNaN(srp) ? null : srp,
      vendor: null, hpp: null, qty: null,
      notes: notes || null,
      picture_urls: [],
      added_by: currentUser, date_added: new Date().toISOString()
    };
    const {error} = await sb.from('product_dev').insert(payload);
    if (error) throw error;

    if (pdPicsToUpload.length) {
      fb.textContent = 'Mengunggah foto...';
      const urls = [];
      for (const f of pdPicsToUpload) {
        const url = await uploadPDPicture(f, id);
        urls.push(url);
      }
      await sb.from('product_dev').update({picture_urls: urls}).eq('id', id);
    }

    fb.textContent = '✅ Produk tersimpan. Scroll ke bawah untuk tambah variants / bundle items.';
    await fetchPDRows();
    clearPDForm();
    try { renderPDDetailTable(); } catch(rerr) {
      console.error('renderPDDetailTable failed after submit:', rerr);
      fb.textContent = '⚠️ Tersimpan, tapi tampilan tidak refresh. Reload halaman. (' + (rerr.message||rerr) + ')';
      return;
    }
    // Auto-collapse the add form so the new product card is visible
    const body  = document.getElementById('pd-add-body');
    const caret = document.getElementById('pd-add-caret');
    if (body)  body.style.display  = 'none';
    if (caret) caret.textContent   = '▶';
    // Scroll to the new product card
    setTimeout(()=>{
      const listBody = document.getElementById('pdListBody');
      const firstCard = listBody && listBody.querySelector('.pd-card');
      (firstCard || listBody)?.scrollIntoView({behavior:'smooth', block:'start'});
    }, 50);
    setTimeout(()=>{ fb.textContent=''; }, 4000);
  } catch(e) {
    console.error('submitPD error:', e);
    fb.textContent = '❌ Gagal: ' + (e.message||e);
  } finally {
    btn.disabled = false;
  }
}

// ── Detail table render ────────────────────────────────────────────
function getPDDetailFilteredParents() {
  const cid = pdCurrentCollectionId;
  const parents = allPDRows.filter(r => !r.parentId && r.collectionId === cid);
  const subsByParent = {};
  allPDRows.filter(r=>r.parentId).forEach(s => {
    (subsByParent[s.parentId] = subsByParent[s.parentId] || []).push(s);
  });

  const search = pdSearchQuery.toLowerCase();
  const filtered = parents.filter(p => {
    const subs = subsByParent[p.id] || [];
    const isMulti = p.skuType === 'multi' || subs.length > 0;
    if (pdFilters.type === 'solo'  && isMulti) return false;
    if (pdFilters.type === 'multi' && !isMulti) return false;
    if (pdFilters.vendor) {
      const allVendors = [p.vendor, ...subs.map(s=>s.vendor)].filter(Boolean);
      if (!allVendors.includes(pdFilters.vendor)) return false;
    }
    if (search) {
      const hay = `${p.skuName} ${p.displayCode}`.toLowerCase();
      if (!hay.includes(search)) return false;
    }
    return true;
  });

  return {parents: filtered, subsByParent};
}

function renderPDDetailTable() {
  const cid = pdCurrentCollectionId;
  if (!cid) return;
  // Read filters from DOM (in case user changed them)
  pdFilters.vendor = document.getElementById('pd-fil-vendor')?.value || '';
  pdFilters.type   = document.getElementById('pd-fil-type')?.value || '';
  pdSearchQuery    = document.getElementById('pd-search')?.value.trim() || '';

  const host = document.getElementById('pdListBody');
  if (!host) return;
  const {parents, subsByParent} = getPDDetailFilteredParents();

  // Stats: every product has variants. "Single" = 1 variant, "Multi" = >1.
  const allInCol = allPDRows.filter(r => !r.parentId && r.collectionId === cid);
  const subsInCol = {};
  allInCol.forEach(p => { subsInCol[p.id] = (allPDRows.filter(r => r.parentId === p.id)); });
  const singleCount = allInCol.filter(p => (subsInCol[p.id]||[]).length === 1).length;
  const multiCount  = allInCol.filter(p => (subsInCol[p.id]||[]).length >  1).length;
  const totalSRP = allInCol.reduce((s,p) => s + Number(p.srp||0), 0);
  const ratios = allInCol.map(p => pdComputeRatio(p, subsInCol[p.id]||[])).filter(r=>r);
  const avgRatio = ratios.length ? (ratios.reduce((a,b)=>a+b,0)/ratios.length) : null;

  document.getElementById('pd-d-total').textContent = allInCol.length;
  document.getElementById('pd-d-solo').textContent  = singleCount;
  document.getElementById('pd-d-multi').textContent = multiCount;
  document.getElementById('pd-d-srp').textContent   = totalSRP ? 'Rp '+pdFmtIDR(totalSRP) : '—';
  document.getElementById('pd-d-ratio').textContent = avgRatio ? avgRatio.toFixed(2)+'×' : '—';
  document.getElementById('pd-tcount').textContent  = `${parents.length} produk`;

  // Global projection (entire collection)
  const gp = pdComputeGlobalProjection();
  const gpUnits   = document.getElementById('pd-gp-units');
  const gpModal   = document.getElementById('pd-gp-modal');
  const gpRevenue = document.getElementById('pd-gp-revenue');
  const gpMargin  = document.getElementById('pd-gp-margin');
  if (gpUnits)   gpUnits.textContent   = gp.units   ? `${pdFmtIDR(gp.units)} unit` : '—';
  if (gpModal)   gpModal.textContent   = gp.modal   ? 'Rp '+pdFmtIDR(gp.modal)     : '—';
  if (gpRevenue) gpRevenue.textContent = gp.revenue100 ? 'Rp '+pdFmtIDR(gp.revenue100) : '—';
  if (gpMargin) {
    if (gp.revenue100) {
      const pct = gp.grossMarginPct !== null ? ` (${gp.grossMarginPct.toFixed(1)}%)` : '';
      gpMargin.textContent = 'Rp '+pdFmtIDR(gp.grossMargin)+pct;
      gpMargin.style.color = gp.grossMargin > 0 ? '#0a7d3a' : gp.grossMargin < 0 ? '#c33' : '';
    } else {
      gpMargin.textContent = '—';
      gpMargin.style.color = '';
    }
  }

  if (!parents.length) {
    host.innerHTML = `<div class="empty-td" style="padding:32px;text-align:center;color:var(--g400);font-size:12px">${allInCol.length ? 'Tidak ada produk cocok filter.' : 'Belum ada produk. Tambah pakai form di atas.'}</div>`;
    return;
  }

  host.innerHTML = parents.map(p => {
    const subs = subsByParent[p.id] || [];
    if (pdEditingId === p.id) return renderPDParentEditCard(p);
    return renderPDParentCard(p, subs);
  }).join('');
}

function renderPDParentCard(p, allChildren) {
  const subs        = allChildren.filter(c => pdChildKind(c) === 'variant');
  const bundleItems = allChildren.filter(c => pdChildKind(c) === 'bundle_item');
  const proj  = pdComputeProjection(p, allChildren);
  const ratio = proj.ratio;
  const totalHpp = proj.modal;
  const totalQty = proj.units;
  const vendorSet = new Set(allChildren.map(s=>s.vendor).filter(Boolean));
  const vendorTxt = vendorSet.size === 0 ? '—' : vendorSet.size === 1 ? [...vendorSet][0] : `${vendorSet.size} vendors`;
  const code = p.displayCode || p.id;
  const pills = [
    subs.length        ? `<span style="font-size:10px;padding:2px 6px;background:var(--white);border-radius:3px;color:var(--g600);border:1px solid var(--g100);font-weight:500">${subs.length} variant${subs.length===1?'':'s'}</span>` : '',
    bundleItems.length ? `<span style="font-size:10px;padding:2px 6px;background:var(--white);border-radius:3px;color:var(--g600);border:1px solid var(--g100);font-weight:500">📦 ${bundleItems.length} bundle item${bundleItems.length===1?'':'s'}</span>` : ''
  ].filter(Boolean).join(' ');
  const ratioPill = ratio ? `<span class="pill ${ratio>=2.5?'p-active':(ratio>=1.8?'p-review':'p-near')}" style="font-size:10px">${ratio.toFixed(2)}×</span>` : '<span style="color:var(--g400);font-size:11px">—</span>';

  const variantsHTML = subs.length ? subs.map(s => {
    if (pdEditingId === s.id) return renderPDVariantEditCard(s, p.id);
    return renderPDVariantCard(s, p.id);
  }).join('') : '<div style="font-size:11px;color:var(--g400);padding:8px 4px;text-align:center">Belum ada variant. Klik + Variant untuk tambah.</div>';

  // Variants section (size/color SKUs of the same product)
  const variantsSection = `<div style="margin-top:10px;padding:10px 12px;border-left:3px solid var(--g100);background:var(--white);border-radius:0 6px 6px 0">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
      <span style="font-size:10px;color:var(--g400);font-family:var(--mono);text-transform:uppercase;letter-spacing:0.5px">Variants (${subs.length}) <span style="color:var(--g200);font-weight:400;text-transform:none;letter-spacing:0">— produk sama, beda size/color</span></span>
      <button class="btn-ghost" style="font-size:11px;padding:3px 10px" onclick="openPDSubForm('${p.id}')">+ Variant</button>
    </div>
    <div id="pd-sub-form-${p.id}"></div>
    ${variantsHTML}
  </div>`;

  // Bundle items section (different products combined into one bundle)
  const bundleHTML = bundleItems.length ? bundleItems.map(b => {
    if (pdEditingId === b.id) return renderPDBundleItemEditCard(b, p.id);
    return renderPDBundleItemCard(b, p.id);
  }).join('') : '<div style="font-size:11px;color:var(--g400);padding:6px 4px;text-align:center">Belum ada bundle item.</div>';

  const bundleSection = `<div style="margin-top:8px;padding:10px 12px;border-left:3px solid var(--g200);background:var(--white);border-radius:0 6px 6px 0">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
      <span style="font-size:10px;color:var(--g400);font-family:var(--mono);text-transform:uppercase;letter-spacing:0.5px">Bundle Items (${bundleItems.length}) <span style="color:var(--g200);font-weight:400;text-transform:none;letter-spacing:0">— produk berbeda dalam 1 paket</span></span>
      <button class="btn-ghost" style="font-size:11px;padding:3px 10px" onclick="openPDBundleForm('${p.id}')">+ Bundle Item</button>
    </div>
    <div id="pd-bundle-form-${p.id}"></div>
    ${bundleHTML}
  </div>`;

  const childrenBlock = `<div id="pd-sub-${p.id}">${variantsSection}${bundleSection}</div>`;

  return `<div class="pd-card" style="display:flex;gap:14px;align-items:flex-start;border:1px solid var(--g100);border-radius:6px;padding:12px;background:var(--off);margin-bottom:10px">
    <div style="flex:0 0 110px">${renderPDPicsLeft(p, 110)}</div>
    <div style="flex:1;min-width:0">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:6px">
        <div style="min-width:0">
          <div style="font-family:var(--mono);font-size:11px;color:var(--g400);font-weight:600;letter-spacing:0.5px">${code}</div>
          <div style="font-size:15px;font-weight:600;margin-top:2px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
            <span>${p.skuName.replace(/</g,'&lt;')}</span> ${pills}
          </div>
        </div>
        <div style="display:flex;gap:4px;flex-shrink:0">
          <button class="btn-ghost" style="font-size:11px;padding:3px 8px" onclick="openPDParentEdit('${p.id}')">✎ Edit</button>
          <button class="btn-ghost" style="font-size:11px;padding:3px 8px;color:#c33" onclick="deletePD('${p.id}',true)">🗑</button>
        </div>
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:16px;font-size:12px;color:var(--g600)">
        <span>Vendor: <b style="color:var(--black)">${vendorTxt.replace(/</g,'&lt;')}</b></span>
        <span>HPP/unit: <span class="mono"><b style="color:var(--black)">${proj.unitCost?pdFmtIDR(Math.round(proj.unitCost)):'—'}</b></span></span>
        <span>SRP: <span class="mono"><b style="color:var(--black)">${pdFmtIDR(p.srp)}</b></span></span>
        <span>Ratio: ${ratioPill}</span>
      </div>
      ${renderPDProjectionRow(proj)}
      ${p.notes ? `<div style="margin-top:6px;font-size:11px;color:var(--g600);font-style:italic">${p.notes.replace(/</g,'&lt;')}</div>` : ''}
      ${childrenBlock}
    </div>
  </div>`;
}

// Business projection strip shown inside each product card.
function renderPDProjectionRow(proj) {
  if (!proj.units) return '';  // nothing to project
  const margin = proj.grossMargin;
  const marginColor = margin > 0 ? '#0a7d3a' : margin < 0 ? '#c33' : 'var(--g600)';
  const pctStr = proj.grossMarginPct !== null ? ` (${proj.grossMarginPct.toFixed(1)}%)` : '';
  const hasRevenue = proj.revenue100 > 0;
  return `<div style="margin-top:10px;padding:10px 12px;background:rgba(0,0,0,0.04);border-radius:6px;display:flex;flex-wrap:wrap;gap:18px;font-size:11px;color:var(--g600)">
    <span style="font-family:var(--mono);font-size:10px;color:var(--g400);text-transform:uppercase;letter-spacing:0.5px;align-self:center">📊 Projection (100% sold)</span>
    <span>Diproduksi: <b style="color:var(--black)" class="mono">${proj.units}</b> unit</span>
    <span>Modal: <b style="color:var(--black)" class="mono">${proj.modal?'Rp '+pdFmtIDR(proj.modal):'—'}</b></span>
    <span>Revenue: <b style="color:var(--black)" class="mono">${hasRevenue?'Rp '+pdFmtIDR(proj.revenue100):'—'}</b></span>
    <span>Gross margin: <b style="color:${marginColor}" class="mono">${hasRevenue?'Rp '+pdFmtIDR(margin)+pctStr:'—'}</b></span>
  </div>`;
}

function renderPDVariantCard(s, parentId) {
  // Variants inherit the parent product's pictures (read-only — no own upload).
  const parent = allPDRows.find(r => r.id === parentId);
  const parentPic = parent && parent.pictures && parent.pictures[0];
  const thumb = parentPic
    ? `<a href="${parentPic}" target="_blank" title="Foto parent: ${(parent.skuName||'').replace(/"/g,'&quot;')}"><img src="${parentPic}" style="width:48px;height:48px;object-fit:cover;border-radius:4px;border:1px solid var(--g100);display:block"></a>`
    : `<div style="width:48px;height:48px;border:1px dashed var(--g100);border-radius:4px;background:var(--off);display:flex;align-items:center;justify-content:center;color:var(--g400);font-size:9px;text-align:center;line-height:1.1">no<br>pic</div>`;

  const sizeTag  = s.size  ? `<span style="font-size:11px;padding:3px 8px;background:var(--black);color:var(--white);border-radius:3px;font-weight:600;letter-spacing:0.5px;font-family:var(--mono)">${s.size.replace(/</g,'&lt;')}</span>` : '';
  const colorTag = s.color ? `<span style="font-size:10px;padding:2px 6px;background:var(--white);border:1px solid var(--g200);border-radius:3px;font-weight:500">${s.color.replace(/</g,'&lt;')}</span>` : '';
  const otherTag = s.variant && s.variant !== (s.size||'') && s.variant !== pdVariantToken(s.size) ? `<span style="font-size:10px;padding:2px 6px;background:var(--off);border:1px solid var(--g100);border-radius:3px;color:var(--g600)">${s.variant.replace(/</g,'&lt;')}</span>` : '';

  return `<div class="pd-subcard" style="display:flex;justify-content:space-between;align-items:center;gap:10px;padding:8px 12px;background:var(--white);border:1px solid var(--g100);border-radius:5px;margin-bottom:6px">
    <div style="flex:0 0 48px">${thumb}</div>
    <div style="min-width:0;flex:1">
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
        <span style="font-family:var(--mono);font-size:10px;color:var(--g400);font-weight:600">${(s.displayCode||'—').replace(/</g,'&lt;')}</span>
        ${sizeTag} ${colorTag} ${otherTag}
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:14px;margin-top:4px;font-size:11px;color:var(--g600)">
        <span>Vendor: <b style="color:var(--black)">${(s.vendor||'—').replace(/</g,'&lt;')}</b></span>
        <span>HPP: <span class="mono"><b style="color:var(--black)">${pdFmtIDR(s.hpp)}</b></span></span>
        <span>QTY: <span class="mono"><b style="color:var(--black)">${s.qty||'—'}</b></span></span>
      </div>
    </div>
    <div style="display:flex;gap:3px;flex-shrink:0">
      <button class="btn-ghost" style="font-size:10px;padding:2px 6px" onclick="openPDSubEdit('${s.id}','${parentId}')">✎</button>
      <button class="btn-ghost" style="font-size:10px;padding:2px 6px;color:#c33" onclick="deletePD('${s.id}',false,'${parentId}')">🗑</button>
    </div>
  </div>`;
}

// ── Bundle item display + edit cards ────────────────────────────────
function renderPDBundleItemCard(b, parentId) {
  // Bundle items have their own pictures (different product).
  return `<div class="pd-subcard" style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;padding:8px 12px;background:var(--white);border:1px solid var(--g100);border-radius:5px;margin-bottom:6px">
    <div style="flex:0 0 60px">${renderPDPicsLeft(b, 60)}</div>
    <div style="min-width:0;flex:1">
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
        <span style="font-family:var(--mono);font-size:10px;color:var(--g400);font-weight:600">${(b.displayCode||'—').replace(/</g,'&lt;')}</span>
        <span style="font-size:12px;font-weight:500">📦 ${(b.skuName||'—').replace(/</g,'&lt;')}</span>
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:14px;margin-top:4px;font-size:11px;color:var(--g600)">
        <span>Vendor: <b style="color:var(--black)">${(b.vendor||'—').replace(/</g,'&lt;')}</b></span>
        <span>HPP: <span class="mono"><b style="color:var(--black)">${pdFmtIDR(b.hpp)}</b></span></span>
        <span>QTY: <span class="mono"><b style="color:var(--black)">${b.qty||'—'}</b></span></span>
      </div>
    </div>
    <div style="display:flex;gap:3px;flex-shrink:0">
      <button class="btn-ghost" style="font-size:10px;padding:2px 6px" onclick="openPDSubEdit('${b.id}','${parentId}')">✎</button>
      <button class="btn-ghost" style="font-size:10px;padding:2px 6px;color:#c33" onclick="deletePD('${b.id}',false,'${parentId}')">🗑</button>
    </div>
  </div>`;
}

function renderPDBundleItemEditCard(b, parentId) {
  return `<div class="pd-subcard" style="display:flex;gap:10px;align-items:flex-start;padding:8px 12px;background:var(--white);border:2px solid var(--black);border-radius:5px;margin-bottom:6px">
    <div style="flex:0 0 60px">${renderPDPicsLeft(b, 60)}</div>
    <div style="flex:1;min-width:0">
      <div style="font-family:var(--mono);font-size:10px;color:var(--g400);font-weight:600;margin-bottom:8px">EDITING BUNDLE ITEM · ${(b.displayCode||b.id).replace(/</g,'&lt;')}</div>
      <div style="display:grid;grid-template-columns:1.6fr 1fr 0.7fr 0.6fr;gap:6px;align-items:end">
        <div><label style="font-size:10px;color:var(--g400)">Item Name *</label><input id="pdbe-name-${b.id}" type="text" value="${(b.skuName||'').replace(/"/g,'&quot;')}" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
        <div><label style="font-size:10px;color:var(--g400)">Vendor</label>${pdVendorSelectHTML(`pdbe-vendor-${b.id}`, b.vendor||'')}</div>
        <div><label style="font-size:10px;color:var(--g400)">HPP</label><input id="pdbe-hpp-${b.id}" type="number" min="0" value="${b.hpp==null?'':b.hpp}" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
        <div><label style="font-size:10px;color:var(--g400)">QTY *</label><input id="pdbe-qty-${b.id}" type="number" min="0" value="${b.qty==null?'':b.qty}" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
      </div>
      <div style="display:flex;gap:6px;margin-top:8px">
        <button class="btn-save" style="font-size:11px;padding:4px 10px" onclick="savePDBundleItemEdit('${b.id}','${parentId}')">💾 Simpan</button>
        <button class="btn-cancel" style="font-size:11px;padding:4px 10px" onclick="cancelPDEdit()">✕ Batal</button>
      </div>
    </div>
  </div>`;
}

function openPDBundleForm(parentId) {
  const host = document.getElementById(`pd-bundle-form-${parentId}`);
  if (!host) return;
  if (host.dataset.open === '1') { host.dataset.open=''; host.innerHTML=''; return; }
  host.dataset.open='1';
  const previewCode = generateNextBundleCode(parentId);
  host.innerHTML = `<div style="background:var(--off);padding:10px 12px;border-radius:4px;margin-bottom:8px">
    <div style="font-size:11px;color:var(--g600);font-family:var(--mono);margin-bottom:8px">Bundle Item Code (auto): <b style="color:var(--black)">${previewCode}</b></div>
    <div style="display:grid;grid-template-columns:1.6fr 1fr 0.7fr 0.6fr auto auto;gap:6px;align-items:end">
      <div><label style="font-size:10px;color:var(--g400)">Item Name *</label><input id="pdb-name-${parentId}" type="text" placeholder="cth: MDB T-shirt L, Free Sticker..." style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
      <div><label style="font-size:10px;color:var(--g400)">Vendor</label>${pdVendorSelectHTML(`pdb-vendor-${parentId}`,'')}</div>
      <div><label style="font-size:10px;color:var(--g400)">HPP (Rp)</label><input id="pdb-hpp-${parentId}" type="number" min="0" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
      <div><label style="font-size:10px;color:var(--g400)">QTY *</label><input id="pdb-qty-${parentId}" type="number" min="0" value="1" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
      <button class="btn-save" style="font-size:10px;padding:4px 10px" onclick="submitPDBundleItem('${parentId}')">Simpan</button>
      <button class="btn-cancel" style="font-size:10px;padding:4px 8px" onclick="openPDBundleForm('${parentId}')">Batal</button>
    </div>
    <div style="font-size:10px;color:var(--g400);margin-top:4px">Komponen produk yang berbeda — dijual jadi 1 paket bundle.</div>
  </div>`;
}

async function submitPDBundleItem(parentId) {
  const name   = document.getElementById(`pdb-name-${parentId}`).value.trim();
  const vendor = document.getElementById(`pdb-vendor-${parentId}`).value.trim();
  const hpp    = parseFloat(document.getElementById(`pdb-hpp-${parentId}`).value);
  const qty    = parseFloat(document.getElementById(`pdb-qty-${parentId}`).value);
  if (!name) { alert('Item name wajib.'); return; }
  if (isNaN(qty) || qty <= 0) { alert('QTY wajib (> 0).'); return; }
  const parent = allPDRows.find(r=>r.id===parentId);
  const code = generateNextBundleCode(parentId);
  try {
    const id = genId('PDB');
    const {error} = await sb.from('product_dev').insert({
      id, parent_id: parentId,
      collection_id: parent?.collectionId || null,
      display_code: code,
      sku_type: 'bundle_item',
      sku_name: name,
      vendor: vendor||null,
      hpp: isNaN(hpp)?null:hpp,
      qty: isNaN(qty)?null:qty,
      picture_urls: [], added_by: currentUser, date_added: new Date().toISOString()
    });
    if (error) throw error;
    await fetchPDRows();
    renderPDDetailTable();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

async function savePDBundleItemEdit(id, parentId) {
  const r = allPDRows.find(x=>x.id===id);
  if (!r) return;
  const name = document.getElementById(`pdbe-name-${id}`).value.trim();
  const vendor = document.getElementById(`pdbe-vendor-${id}`).value.trim();
  const hppS = document.getElementById(`pdbe-hpp-${id}`).value;
  const qtyS = document.getElementById(`pdbe-qty-${id}`).value;
  if (!name) { alert('Item name wajib.'); return; }
  if (qtyS === '' || Number(qtyS) <= 0) { alert('QTY wajib (> 0).'); return; }
  const upd = {
    sku_name: name,
    vendor: vendor||null,
    hpp: hppS===''?null:parseFloat(hppS),
    qty: qtyS===''?null:parseFloat(qtyS),
    last_updated: new Date().toISOString(), last_updated_by: currentUser
  };
  const {error} = await sb.from('product_dev').update(upd).eq('id',id);
  if (error) { alert('Gagal: '+error.message); return; }
  pdEditingId = '';
  await fetchPDRows();
  renderPDDetailTable();
}

// ── Inline edit cards (replace the prompt() popups) ─────────────────
function renderPDParentEditCard(p) {
  return `<div class="pd-card" style="display:flex;gap:14px;align-items:flex-start;border:2px solid var(--black);border-radius:6px;padding:12px;background:var(--white);margin-bottom:10px">
    <div style="flex:0 0 110px">${renderPDPicsLeft(p, 110)}</div>
    <div style="flex:1;min-width:0">
      <div style="font-family:var(--mono);font-size:11px;color:var(--g400);font-weight:600;margin-bottom:8px">EDITING · ${(p.displayCode||p.id).replace(/</g,'&lt;')}</div>
      <div class="form-grid" style="grid-template-columns:2fr 1fr;gap:8px">
        <div class="fg"><label style="font-size:11px">Nama Produk *</label><input id="pde-name-${p.id}" type="text" value="${(p.skuName||'').replace(/"/g,'&quot;')}" style="font-size:12px;padding:5px 8px"></div>
        <div class="fg"><label style="font-size:11px">SRP (Rp)</label><input id="pde-srp-${p.id}" type="number" min="0" value="${p.srp==null?'':p.srp}" style="font-size:12px;padding:5px 8px"></div>
        <div class="fg full"><label style="font-size:11px">Notes</label><input id="pde-notes-${p.id}" type="text" value="${(p.notes||'').replace(/"/g,'&quot;')}" style="font-size:12px;padding:5px 8px"></div>
      </div>
      <div style="display:flex;gap:6px;margin-top:10px">
        <button class="btn-save" style="font-size:11px;padding:5px 12px" onclick="savePDParentEdit('${p.id}')">💾 Simpan</button>
        <button class="btn-cancel" style="font-size:11px;padding:5px 12px" onclick="cancelPDEdit()">✕ Batal</button>
      </div>
    </div>
  </div>`;
}

function renderPDVariantEditCard(s, parentId) {
  // Size: dropdown with the standard options + the current value if it's custom (e.g., a legacy entry)
  const sizeOpts = [...new Set([...PD_SIZE_OPTIONS, s.size||''].filter(Boolean))]
    .map(v => `<option value="${v}"${v===(s.size||'')?' selected':''}>${v}</option>`).join('');
  return `<div class="pd-subcard" style="padding:10px 12px;background:var(--white);border:2px solid var(--black);border-radius:5px;margin-bottom:6px">
    <div style="font-family:var(--mono);font-size:10px;color:var(--g400);font-weight:600;margin-bottom:8px">EDITING · ${(s.displayCode||s.id).replace(/</g,'&lt;')}</div>
    <div style="display:grid;grid-template-columns:100px 1.4fr 0.8fr 0.7fr;gap:8px;align-items:end">
      <div><label style="font-size:10px;color:var(--g400)">Size</label>
        <select id="pde-size-${s.id}" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%;font-family:var(--mono);background:var(--white)">
          <option value="">—</option>${sizeOpts}
        </select>
      </div>
      <div><label style="font-size:10px;color:var(--g400)">Vendor</label>${pdVendorSelectHTML(`pde-vendor-${s.id}`, s.vendor||'')}</div>
      <div><label style="font-size:10px;color:var(--g400)">HPP (Rp)</label><input id="pde-hpp-${s.id}" type="number" min="0" value="${s.hpp==null?'':s.hpp}" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
      <div><label style="font-size:10px;color:var(--g400)">QTY *</label><input id="pde-qty-${s.id}" type="number" min="0" value="${s.qty==null?'':s.qty}" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
    </div>
    <div style="display:flex;gap:6px;margin-top:8px">
      <button class="btn-save" style="font-size:11px;padding:4px 10px" onclick="savePDVariantEdit('${s.id}','${parentId}')">💾 Simpan</button>
      <button class="btn-cancel" style="font-size:11px;padding:4px 10px" onclick="cancelPDEdit()">✕ Batal</button>
    </div>
  </div>`;
}

// Picture column for the left side of cards.
// size = pixel size of the square (parent 110, sub 60)
function renderPDPicsLeft(r, size) {
  const pics = r.pictures||[];
  const px = size;
  const items = [];

  // Main image area: shows pic 1 large, or placeholder
  if (pics.length >= 1) {
    items.push(`<div style="position:relative;width:${px}px;height:${px}px">
      <a href="${pics[0]}" target="_blank"><img src="${pics[0]}" style="width:100%;height:100%;object-fit:cover;border-radius:4px;border:1px solid var(--g100);background:var(--white);display:block"></a>
      <button class="btn-ghost" style="position:absolute;top:2px;right:2px;font-size:9px;padding:1px 5px;background:rgba(255,255,255,0.9);border-radius:3px;color:#c33;line-height:1" title="Hapus foto" onclick="removePDPicture('${r.id}','${pics[0].replace(/'/g,"\\'")}')">×</button>
    </div>`);
  } else {
    items.push(`<div style="width:${px}px;height:${px}px;display:flex;align-items:center;justify-content:center;background:var(--white);border:1px dashed var(--g100);border-radius:4px;color:var(--g400);font-size:${Math.max(10,size/8)}px;cursor:pointer" onclick="pickPicForRecord('${r.id}')" title="Tambah foto">+ Foto</div>`);
  }

  // Secondary image: pic 2 or "+" button if room
  if (pics.length >= 2) {
    const sec = Math.round(px * 0.45);
    items.push(`<div style="position:relative;width:${px}px;height:${sec}px;margin-top:4px">
      <a href="${pics[1]}" target="_blank"><img src="${pics[1]}" style="width:100%;height:100%;object-fit:cover;border-radius:4px;border:1px solid var(--g100);background:var(--white);display:block"></a>
      <button class="btn-ghost" style="position:absolute;top:2px;right:2px;font-size:9px;padding:1px 5px;background:rgba(255,255,255,0.9);border-radius:3px;color:#c33;line-height:1" title="Hapus foto" onclick="removePDPicture('${r.id}','${pics[1].replace(/'/g,"\\'")}')">×</button>
    </div>`);
  } else if (pics.length === 1) {
    const sec = Math.round(px * 0.32);
    items.push(`<div style="width:${px}px;height:${sec}px;margin-top:4px;display:flex;align-items:center;justify-content:center;background:var(--white);border:1px dashed var(--g100);border-radius:4px;color:var(--g400);font-size:${Math.max(9,size/10)}px;cursor:pointer" onclick="pickPicForRecord('${r.id}')" title="Tambah foto ke-2">+ Foto 2</div>`);
  }

  return `<div style="display:flex;flex-direction:column">${items.join('')}</div>`;
}

// Backward-compat shim (no longer used in the card layout, kept in case anything calls it)
function renderPDPicsCell(r) {
  return renderPDPicsLeft(r, 40);
}

function togglePDExpand(parentId) {
  const row = document.getElementById(`pd-sub-${parentId}`);
  const caret = document.getElementById(`pd-caret-${parentId}`);
  if (!row) return;
  if (row.style.display === 'none') { row.style.display = ''; if (caret) caret.textContent='▼'; }
  else { row.style.display = 'none'; if (caret) caret.textContent='▶'; }
}

// Toggle a size chip's selected state.
function togglePDSizeChip(btn) {
  btn.classList.toggle('pd-size-active');
  // Toggle inline styles since we can't rely on CSS class
  const active = btn.classList.contains('pd-size-active');
  btn.style.background = active ? 'var(--black)' : 'var(--white)';
  btn.style.color      = active ? 'var(--white)' : 'var(--black)';
  btn.style.borderColor= active ? 'var(--black)' : 'var(--g100)';
}

function pdVendorSelectHTML(id, current) {
  const opts = pdAllVendors.map(v => {
    const sel = (v.toLowerCase() === (current||'').toLowerCase()) ? ' selected' : '';
    return `<option value="${v.replace(/"/g,'&quot;')}"${sel}>${v.replace(/</g,'&lt;')}</option>`;
  }).join('');
  return `<select id="${id}" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%;background:var(--white)">
    <option value="">— Pilih vendor —</option>
    ${opts}
  </select>`;
}

function openPDSubForm(parentId) {
  const host = document.getElementById(`pd-sub-form-${parentId}`);
  if (!host) return;
  if (host.dataset.open === '1') { host.dataset.open=''; host.innerHTML=''; return; }
  host.dataset.open='1';
  const sizeChips = PD_SIZE_OPTIONS.map(s =>
    `<button type="button" class="pd-size-chip" data-size="${s}" onclick="togglePDSizeChip(this)" style="font-size:11px;padding:5px 12px;border:1px solid var(--g100);border-radius:4px;background:var(--white);color:var(--black);cursor:pointer;font-family:var(--mono);font-weight:600">${s}</button>`
  ).join(' ');
  host.innerHTML = `<div style="background:var(--off);padding:12px;border-radius:4px;margin-bottom:8px">
    <div style="margin-bottom:10px">
      <label style="font-size:11px;color:var(--g400);display:block;margin-bottom:4px">Sizes * <span style="color:var(--g300);font-weight:400">(pilih satu atau lebih — tiap size = SKU terpisah)</span></label>
      <div id="pdv-sizes-${parentId}" style="display:flex;gap:6px;flex-wrap:wrap">${sizeChips}</div>
    </div>
    <div style="display:grid;grid-template-columns:1.4fr 0.8fr 0.7fr auto auto;gap:8px;align-items:end">
      <div><label style="font-size:10px;color:var(--g400)">Vendor</label>${pdVendorSelectHTML(`pdv-vendor-${parentId}`,'')}</div>
      <div><label style="font-size:10px;color:var(--g400)">HPP per unit (Rp)</label><input id="pdv-hpp-${parentId}" type="number" min="0" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
      <div><label style="font-size:10px;color:var(--g400)">QTY per size *</label><input id="pdv-qty-${parentId}" type="number" min="0" value="1" style="font-size:11px;padding:4px 6px;border:1px solid var(--g100);border-radius:3px;width:100%"></div>
      <button class="btn-save" style="font-size:10px;padding:5px 12px" onclick="submitPDSubItem('${parentId}')">Simpan</button>
      <button class="btn-cancel" style="font-size:10px;padding:5px 10px" onclick="openPDSubForm('${parentId}')">Batal</button>
    </div>
    <div style="font-size:10px;color:var(--g400);margin-top:6px">Vendor, HPP, dan QTY di-apply ke semua size yang dipilih. Edit per-variant kalau perlu beda.</div>
  </div>`;
}

async function submitPDSubItem(parentId) {
  const chipsHost = document.getElementById(`pdv-sizes-${parentId}`);
  const selectedSizes = chipsHost
    ? [...chipsHost.querySelectorAll('.pd-size-chip.pd-size-active')].map(b => b.dataset.size)
    : [];
  const vendor = document.getElementById(`pdv-vendor-${parentId}`).value.trim();
  const hpp    = parseFloat(document.getElementById(`pdv-hpp-${parentId}`).value);
  const qty    = parseFloat(document.getElementById(`pdv-qty-${parentId}`).value);
  if (!selectedSizes.length) { alert('Pilih minimal satu size.'); return; }
  if (isNaN(qty) || qty <= 0) { alert('QTY wajib (> 0).'); return; }
  const parent = allPDRows.find(r=>r.id===parentId);
  try {
    // Insert one row per selected size
    const rows = selectedSizes.map(size => ({
      id: genId('PDV'),
      parent_id: parentId,
      collection_id: parent?.collectionId || null,
      display_code: generateNextVariantCode(parent?.collectionId||'', size),
      sku_type: 'variant',
      sku_name: parent?.skuName || null,
      size, color: null, variant: null,
      vendor: vendor||null,
      hpp: isNaN(hpp)?null:hpp,
      qty: isNaN(qty)?null:qty,
      picture_urls: [],
      added_by: currentUser, date_added: new Date().toISOString()
    }));
    // Bump sequence numbers manually so codes are unique within this batch
    // (generateNextVariantCode reads allPDRows which won't include in-flight rows)
    const seen = {};
    rows.forEach(r => {
      const baseSize = r.size;
      const base = r.display_code;
      if (seen[baseSize]) {
        // Increment the NN suffix manually
        const m = base.match(/-(\d{2,})$/);
        if (m) {
          const next = String(parseInt(m[1],10) + seen[baseSize]).padStart(2,'0');
          r.display_code = base.replace(/-(\d{2,})$/, `-${next}`);
        }
      }
      seen[baseSize] = (seen[baseSize]||0) + 1;
    });
    const {error} = await sb.from('product_dev').insert(rows);
    if (error) throw error;
    await fetchPDRows();
    renderPDDetailTable();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

// Enter inline-edit mode for a parent product.
function openPDParentEdit(id) {
  pdEditingId = id;
  renderPDDetailTable();
}

// Enter inline-edit mode for a variant or bundle item.
function openPDSubEdit(id, parentId) {
  pdEditingId = id;
  renderPDDetailTable();
}

function cancelPDEdit() {
  pdEditingId = '';
  renderPDDetailTable();
}

async function savePDParentEdit(id) {
  const r = allPDRows.find(x=>x.id===id);
  if (!r) return;
  const name  = (document.getElementById(`pde-name-${id}`).value||'').trim();
  const srpS  = document.getElementById(`pde-srp-${id}`).value;
  const notes = (document.getElementById(`pde-notes-${id}`).value||'').trim();
  if (!name) { alert('Nama produk wajib.'); return; }
  const upd = {
    sku_name: name,
    srp: srpS===''?null:parseFloat(srpS),
    notes: notes || null,
    last_updated: new Date().toISOString(), last_updated_by: currentUser
  };
  const {error} = await sb.from('product_dev').update(upd).eq('id',id);
  if (error) { alert('Gagal: '+error.message); return; }
  pdEditingId = '';
  await fetchPDRows();
  renderPDDetailTable();
}

async function savePDVariantEdit(id, parentId) {
  const r = allPDRows.find(x=>x.id===id);
  if (!r) return;
  const size   = document.getElementById(`pde-size-${id}`).value.trim();
  const vendor = document.getElementById(`pde-vendor-${id}`).value.trim();
  const hppS   = document.getElementById(`pde-hpp-${id}`).value;
  const qtyS   = document.getElementById(`pde-qty-${id}`).value;
  if (!size) { alert('Size wajib.'); return; }
  if (qtyS === '' || Number(qtyS) <= 0) { alert('QTY wajib (> 0).'); return; }

  // Regenerate code if size changed
  let displayCode = r.displayCode;
  if (pdVariantToken(size) !== pdVariantToken(r.size||'')) {
    displayCode = generateNextVariantCode(r.collectionId, size);
  }
  const upd = {
    display_code: displayCode,
    size: size||null,
    color: null, variant: null,  // clear legacy color/other on edit
    vendor: vendor||null,
    hpp: hppS===''?null:parseFloat(hppS),
    qty: qtyS===''?null:parseFloat(qtyS),
    last_updated: new Date().toISOString(), last_updated_by: currentUser
  };
  const {error} = await sb.from('product_dev').update(upd).eq('id',id);
  if (error) { alert('Gagal: '+error.message); return; }
  pdEditingId = '';
  await fetchPDRows();
  renderPDDetailTable();
}

async function deletePD(id, isParent, parentId) {
  const r = allPDRows.find(x=>x.id===id);
  if (!r) return;
  const msg = isParent
    ? `Hapus SKU "${r.skuName}" (${r.displayCode||r.id}) beserta semua sub-items & foto?`
    : `Hapus sub-item "${r.skuName}" (${r.displayCode||r.id})?`;
  if (!confirm(msg)) return;
  try {
    const toDelete = [r];
    if (isParent) allPDRows.filter(x => x.parentId === id).forEach(s => toDelete.push(s));
    const storagePaths = [];
    toDelete.forEach(x => (x.pictures||[]).forEach(u=>{
      const marker = `/${PD_BUCKET}/`;
      const idx = u.indexOf(marker);
      if (idx >= 0) storagePaths.push(u.slice(idx + marker.length));
    }));
    if (storagePaths.length) await sb.storage.from(PD_BUCKET).remove(storagePaths);
    const {error} = await sb.from('product_dev').delete().eq('id', id);
    if (error) throw error;
    await fetchPDRows();
    renderPDDetailTable();
  } catch(e) { alert('Gagal hapus: '+(e.message||e)); }
}

// ── PDF EXPORT (catalog cards via print window) ────────────────────
function pdEsc(s) {
  return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function buildPDCatalogHTML(title, parents, subsByParent, mode, vendor) {
  // mode: 'internal' | 'external' | 'vendor'
  const collName = pdCollName(pdCurrentCollectionId);
  const today = new Date().toLocaleDateString('id-ID',{day:'2-digit',month:'long',year:'numeric'});
  const showVendor = mode === 'internal' || mode === 'vendor';
  const showHPP    = mode === 'internal' || mode === 'vendor';
  const showSRP    = mode === 'internal' || mode === 'external';
  const showRatio  = mode === 'internal';

  const cardsHTML = parents.map(p => {
    const all = subsByParent[p.id] || [];
    const variants    = all.filter(c => pdChildKind(c) === 'variant');
    const bundleItems = all.filter(c => pdChildKind(c) === 'bundle_item');
    const proj = pdComputeProjection(p, all);
    const ratio = proj.ratio;
    const totalHpp = proj.modal;
    const totalQty = proj.units;
    const pics = p.pictures||[];
    const pic1 = pics[0] || '';
    const pic2 = pics[1] || '';

    // Vendor-mode filter applied to children
    const filterByVendor = arr => (mode === 'vendor' && vendor)
      ? arr.filter(s => (s.vendor||'').toLowerCase() === vendor.toLowerCase())
      : arr;
    const fVariants    = filterByVendor(variants);
    const fBundleItems = filterByVendor(bundleItems);

    // In vendor mode, drop the whole product if no matching children
    if (mode === 'vendor' && fVariants.length === 0 && fBundleItems.length === 0) return '';

    const variantRow = (s) => `<tr>
      <td class="mono">${pdEsc(s.displayCode||'—')}</td>
      <td class="mono">${pdEsc(s.size||'—')}</td>
      ${showVendor ? `<td>${pdEsc(s.vendor||'—')}</td>` : ''}
      ${showHPP ? `<td class="r mono">${s.hpp?'Rp '+pdFmtIDR(s.hpp):'—'}</td>` : ''}
      <td class="r mono">${s.qty||'—'}</td>
    </tr>`;
    const bundleRow = (b) => {
      const pic = (b.pictures||[])[0];
      const picCell = pic
        ? `<img src="${pdEsc(pic)}" style="width:36px;height:36px;object-fit:cover;border-radius:3px;border:1px solid #ddd;display:block">`
        : '<span style="color:#bbb;font-size:9px">—</span>';
      return `<tr>
        <td style="width:42px">${picCell}</td>
        <td class="mono">${pdEsc(b.displayCode||'—')}</td>
        <td>${pdEsc(b.skuName||'—')}</td>
        ${showVendor ? `<td>${pdEsc(b.vendor||'—')}</td>` : ''}
        ${showHPP ? `<td class="r mono">${b.hpp?'Rp '+pdFmtIDR(b.hpp):'—'}</td>` : ''}
        <td class="r mono">${b.qty||'—'}</td>
      </tr>`;
    };

    const variantsHTML = fVariants.length ? `<div style="margin-top:8px;font-size:10px;color:#666;text-transform:uppercase;letter-spacing:0.5px">Variants</div>
      <table class="subs">
        <thead><tr>
          <th>Code</th><th>Size</th>
          ${showVendor ? '<th>Vendor</th>' : ''}
          ${showHPP ? '<th class="r">HPP</th>' : ''}
          <th class="r">QTY</th>
        </tr></thead>
        <tbody>${fVariants.map(variantRow).join('')}</tbody>
      </table>` : '';

    const bundleHTML = fBundleItems.length ? `<div style="margin-top:10px;font-size:10px;color:#666;text-transform:uppercase;letter-spacing:0.5px">Bundle Items</div>
      <table class="subs">
        <thead><tr>
          <th style="width:42px"></th><th>Code</th><th>Item Name</th>
          ${showVendor ? '<th>Vendor</th>' : ''}
          ${showHPP ? '<th class="r">HPP</th>' : ''}
          <th class="r">QTY</th>
        </tr></thead>
        <tbody>${fBundleItems.map(bundleRow).join('')}</tbody>
      </table>` : '';

    const typeLabel = bundleItems.length && variants.length ? 'Bundle + variants'
                    : bundleItems.length ? 'Bundle'
                    : variants.length    ? `${variants.length} variant${variants.length===1?'':'s'}`
                    : 'Product';

    return `<section class="card">
      <div class="card-head">
        <div class="code">${pdEsc(p.displayCode || p.id)}</div>
        <div class="name">${pdEsc(p.skuName)}</div>
        <div class="meta">${pdEsc(typeLabel)} · ${pdEsc(collName)}</div>
      </div>
      <div class="card-body">
        <div class="pics">
          ${pic1 ? `<img src="${pdEsc(pic1)}" alt="">` : '<div class="ph">No photo</div>'}
          ${pic2 ? `<img src="${pdEsc(pic2)}" alt="">` : ''}
        </div>
        <div class="details">
          <table class="kv">
            ${showHPP ? `<tr><th>HPP/unit</th><td class="mono">${proj.unitCost?'Rp '+pdFmtIDR(Math.round(proj.unitCost)):'—'}</td></tr>` : ''}
            <tr><th>Diproduksi</th><td class="mono">${totalQty||'—'} unit</td></tr>
            ${showSRP ? `<tr><th>SRP</th><td class="mono"><b>Rp ${pdFmtIDR(p.srp)}</b></td></tr>` : ''}
            ${showRatio && ratio ? `<tr><th>Ratio SRP/HPP</th><td class="mono"><b>${ratio.toFixed(2)}×</b></td></tr>` : ''}
            ${p.notes ? `<tr><th>Notes</th><td>${pdEsc(p.notes)}</td></tr>` : ''}
          </table>
          ${mode === 'internal' && proj.units ? `
            <div class="proj">
              <div class="proj-label">📊 Projection (100% sold)</div>
              <table class="kv">
                <tr><th>Modal</th><td class="mono">${proj.modal?'Rp '+pdFmtIDR(proj.modal):'—'}</td></tr>
                <tr><th>Revenue</th><td class="mono">${proj.revenue100?'Rp '+pdFmtIDR(proj.revenue100):'—'}</td></tr>
                <tr><th>Gross margin</th><td class="mono"><b>${proj.revenue100?'Rp '+pdFmtIDR(proj.grossMargin):'—'}${proj.grossMarginPct!==null?` (${proj.grossMarginPct.toFixed(1)}%)`:''}</b></td></tr>
              </table>
            </div>` : ''}
          ${variantsHTML}
          ${bundleHTML}
        </div>
      </div>
    </section>`;
  }).filter(Boolean).join('');

  const modeLabel = mode === 'internal' ? 'Internal' : mode === 'external' ? 'External' : `Vendor — ${pdEsc(vendor||'')}`;

  return `<!doctype html><html><head><meta charset="utf-8">
<title>${pdEsc(title)}</title>
<style>
  @page { size: A4; margin: 12mm; }
  * { box-sizing: border-box; }
  body { font-family: -apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif; font-size: 11px; color: #111; margin: 0; padding: 0; }
  header.doc { padding: 0 0 12px; border-bottom: 2px solid #111; margin-bottom: 12px; }
  header.doc h1 { font-size: 20px; margin: 0; letter-spacing: 0.5px; }
  header.doc .sub { font-size: 11px; color: #666; margin-top: 2px; }
  header.doc .badge { display:inline-block;padding:2px 8px;font-size:10px;background:#111;color:#fff;border-radius:3px;margin-top:4px;letter-spacing:0.5px;text-transform:uppercase }
  .card { page-break-inside: avoid; border: 1px solid #ddd; border-radius: 6px; margin: 0 0 14px; padding: 12px; background: #fafaf7; }
  .card-head { border-bottom: 1px solid #ddd; padding-bottom: 8px; margin-bottom: 8px; }
  .card-head .code { font-family: 'SF Mono',Menlo,monospace; font-size: 11px; color: #666; letter-spacing: 0.5px; }
  .card-head .name { font-size: 16px; font-weight: 700; margin-top: 2px; }
  .card-head .meta { font-size: 10px; color: #999; margin-top: 2px; text-transform: uppercase; letter-spacing: 0.5px; }
  .card-body { display: flex; gap: 12px; }
  .pics { flex: 0 0 35%; display: flex; flex-direction: column; gap: 6px; }
  .pics img { width: 100%; max-height: 180px; object-fit: cover; border-radius: 4px; border: 1px solid #ddd; }
  .pics .ph { width: 100%; height: 100px; display: flex; align-items: center; justify-content: center; background: #eee; color: #999; font-size: 10px; border-radius: 4px; }
  .details { flex: 1; min-width: 0; }
  table.kv { width: 100%; border-collapse: collapse; }
  table.kv th, table.kv td { padding: 4px 6px; font-size: 11px; vertical-align: top; }
  table.kv th { text-align: left; color: #666; font-weight: 500; width: 110px; border-bottom: 1px solid #eee; }
  table.kv td { border-bottom: 1px solid #eee; }
  .mono { font-family: 'SF Mono',Menlo,monospace; }
  .r { text-align: right; }
  table.subs { width: 100%; border-collapse: collapse; margin-top: 8px; font-size: 10px; }
  table.subs th, table.subs td { padding: 3px 5px; border-bottom: 1px solid #eee; }
  table.subs th { text-align: left; background: #f3f3ee; color: #555; font-weight: 600; }
  .proj { margin-top: 10px; padding: 8px 10px; background: #fafaf7; border: 1px solid #e0dfd8; border-radius: 4px; }
  .proj-label { font-size: 9px; color: #666; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
  .proj table.kv th { width: 100px; }
  .gp { background: #f3f3ee; border: 1px solid #d6d5cc; border-radius: 6px; padding: 12px 14px; margin-bottom: 14px; page-break-inside: avoid; }
  .gp-title { font-size: 10px; color: #555; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 8px; }
  .gp-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; }
  .gp-lbl { font-size: 9px; color: #777; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 2px; }
  .gp-val { font-family: 'SF Mono',Menlo,monospace; font-size: 14px; font-weight: 700; }
  .empty { padding: 40px; text-align: center; color: #999; }
  @media print { body { -webkit-print-color-adjust: exact; print-color-adjust: exact; } .no-print { display: none; } }
  .no-print { position: fixed; top: 8px; right: 8px; background: #111; color: #fff; padding: 6px 12px; border-radius: 4px; cursor: pointer; border: 0; font-size: 12px; }
</style>
</head><body>
<button class="no-print" onclick="window.print()">🖨 Print / Save as PDF</button>
<header class="doc">
  <h1>${pdEsc(title)}</h1>
  <div class="sub">${pdEsc(collName)} · ${pdEsc(parents.length)} SKU · ${today}</div>
  <span class="badge">${modeLabel}</span>
</header>
${mode === 'internal' ? (() => {
  const gp = pdComputeGlobalProjection();
  if (!gp.units) return '';
  const marginColor = gp.grossMargin > 0 ? '#0a7d3a' : gp.grossMargin < 0 ? '#c33' : '#111';
  const pct = gp.grossMarginPct !== null ? ` (${gp.grossMarginPct.toFixed(1)}%)` : '';
  return `<div class="gp">
    <div class="gp-title">📊 Global Projection · 100% terjual</div>
    <div class="gp-grid">
      <div><div class="gp-lbl">Total Diproduksi</div><div class="gp-val">${pdFmtIDR(gp.units)} unit</div></div>
      <div><div class="gp-lbl">Total Modal</div><div class="gp-val">Rp ${pdFmtIDR(gp.modal)}</div></div>
      <div><div class="gp-lbl">Total Revenue</div><div class="gp-val">Rp ${pdFmtIDR(gp.revenue100)}</div></div>
      <div><div class="gp-lbl">Gross Margin</div><div class="gp-val" style="color:${marginColor}">Rp ${pdFmtIDR(gp.grossMargin)}${pct}</div></div>
    </div>
  </div>`;
})() : ''}
${cardsHTML || '<div class="empty">Tidak ada SKU untuk export ini.</div>'}
</body></html>`;
}

function exportPDPDF(mode) {
  const {parents, subsByParent} = getPDDetailFilteredParents();
  if (!parents.length) { alert('Tidak ada SKU sesuai filter.'); return; }
  const title = mode === 'internal' ? 'Product Dev — Internal' : 'Product Dev — External';
  const html = buildPDCatalogHTML(title, parents, subsByParent, mode, null);
  const w = window.open('', '_blank');
  if (!w) { alert('Pop-up diblokir. Izinkan pop-up untuk export PDF.'); return; }
  w.document.write(html);
  w.document.close();
  // Auto-trigger print once images load
  w.addEventListener('load', () => setTimeout(()=>w.print(), 400));
}

// Toggle a small dropdown listing vendors in the current collection.
// Click a vendor → export PDF for that vendor.
function exportPDVendorPrompt(ev) {
  const cid = pdCurrentCollectionId;
  // Vendors used in this collection (across parent + variant rows)
  const inThisCol = allPDRows.filter(r => {
    if (r.collectionId === cid) return true;
    if (r.parentId) {
      const p = allPDRows.find(x => x.id === r.parentId);
      return p && p.collectionId === cid;
    }
    return false;
  });
  const vendorsHere = [...new Set(inThisCol.map(r => r.vendor).filter(Boolean))].sort();
  if (!vendorsHere.length) { alert('Belum ada vendor di collection ini. Tambah vendor di salah satu variant dulu.'); return; }

  // Toggle dropdown if already open
  const existing = document.getElementById('pd-vendor-dropdown');
  if (existing) { existing.remove(); return; }

  const btn = (ev && ev.currentTarget) || document.querySelector('[onclick*="exportPDVendorPrompt"]');
  const rect = btn ? btn.getBoundingClientRect() : {top:100,left:100,bottom:120,width:120};
  const dropdown = document.createElement('div');
  dropdown.id = 'pd-vendor-dropdown';
  dropdown.style.cssText = `position:fixed;top:${rect.bottom+4}px;left:${rect.left}px;min-width:${Math.max(220,rect.width)}px;max-width:340px;max-height:60vh;overflow-y:auto;background:var(--white);border:1px solid var(--g100);border-radius:6px;box-shadow:0 6px 24px rgba(0,0,0,0.18);z-index:9999;padding:6px`;
  dropdown.innerHTML = `
    <div style="font-size:10px;color:var(--g400);font-family:var(--mono);text-transform:uppercase;letter-spacing:0.5px;padding:4px 8px;border-bottom:1px solid var(--g100);margin-bottom:4px">Pilih vendor</div>
    ${vendorsHere.map(v => `<button class="btn-ghost" style="display:block;width:100%;text-align:left;font-size:12px;padding:6px 10px;border-radius:4px;background:transparent" onclick="exportPDForVendor('${v.replace(/'/g,"\\'").replace(/"/g,'&quot;')}')">${v.replace(/</g,'&lt;')}</button>`).join('')}
  `;
  document.body.appendChild(dropdown);
  // Close on outside click
  setTimeout(()=>{
    const handler = e => {
      if (!dropdown.contains(e.target) && e.target !== btn) {
        dropdown.remove();
        document.removeEventListener('click', handler, true);
      }
    };
    document.addEventListener('click', handler, true);
  }, 0);
}

function exportPDForVendor(vendor) {
  const dd = document.getElementById('pd-vendor-dropdown');
  if (dd) dd.remove();
  const {parents, subsByParent} = getPDDetailFilteredParents();
  const html = buildPDCatalogHTML(`Product Dev — Vendor: ${vendor}`, parents, subsByParent, 'vendor', vendor);
  const w = window.open('', '_blank');
  if (!w) { alert('Pop-up diblokir. Izinkan pop-up untuk export PDF.'); return; }
  w.document.write(html);
  w.document.close();
  w.addEventListener('load', () => setTimeout(()=>w.print(), 400));
}

// ── ROYALTY REPORT ──
let _ryRows = [];        // computed [{ipId, ipName, category, royaltyType, percentage, termin, pphRate, qty, gross, royalty, pphAmount, net, ...}]
let _ryPeriod = '';
let _ryMode = 'month';   // 'month' (single-month view) | 'year' (12-month breakdown)

function rySwitchTab(mode, el) {
  _ryMode = mode;
  document.querySelectorAll('#ry-tabs .tab-btn').forEach(b => b.classList.remove('active'));
  if (el) el.classList.add('active');
  document.getElementById('ry-sel-month').style.display = mode === 'month' ? 'flex' : 'none';
  document.getElementById('ry-sel-year').style.display  = mode === 'year'  ? 'flex' : 'none';
  // Hide previous results — data shape differs per mode, force a fresh Load
  document.getElementById('ry-stats').style.display = 'none';
  document.getElementById('ry-result-wrap').style.display = 'none';
  document.getElementById('ry-result-ip').style.display = 'none';
  const fb = document.getElementById('ry-feedback');
  if (fb) { fb.textContent = ''; fb.className = 'feedback'; }
}

function ryNavPeriod(delta) {
  const inp = document.getElementById('ry-period');
  if (!inp) return;
  const cur = inp.value || new Date().toISOString().slice(0,7);
  if (delta === 0) { inp.value = new Date().toISOString().slice(0,7); return; }
  const [y, m] = cur.split('-').map(Number);
  const d = new Date(y, m - 1 + delta, 1);
  inp.value = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;
}

function _ryRp(n) {
  if (!n) return 'Rp 0';
  return 'Rp ' + new Intl.NumberFormat('id-ID').format(Math.round(Number(n)));
}

function _ryEsc(s) {
  return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

async function loadRoyaltyReport() {
  const fb  = document.getElementById('ry-feedback');
  const btn = document.getElementById('ry-load-btn');

  // Date range depends on the active tab (WIB boundaries)
  let startISO, endISO;
  if (_ryMode === 'year') {
    const year = parseInt(document.getElementById('ry-year').value, 10);
    if (!year) { fb.textContent='Pilih tahun dulu.'; fb.className='feedback err'; return; }
    _ryPeriod = String(year);
    startISO = `${year}-01-01T00:00:00+07:00`;
    endISO   = `${year+1}-01-01T00:00:00+07:00`;
  } else {
    const period = document.getElementById('ry-period').value;
    if (!period) { fb.textContent='Pilih periode dulu.'; fb.className='feedback err'; return; }
    _ryPeriod = period;
    const [y, m] = period.split('-').map(Number);
    const next = new Date(y, m, 1);
    startISO = `${period}-01T00:00:00+07:00`;
    endISO   = `${next.getFullYear()}-${String(next.getMonth()+1).padStart(2,'0')}-01T00:00:00+07:00`;
  }

  fb.textContent = ''; fb.className = 'feedback'; btn.textContent = 'Loading...'; btn.disabled = true;

  try {
    // 1. Pull non-canceled sales orders for the whole year (keep transaction_date for month bucketing)
    const orders = await _fetchAllPages(
      'jubelio_sales_orders',
      'salesorder_id,transaction_date,wms_status,is_canceled,sub_total',
      q => q.gte('transaction_date', startISO).lt('transaction_date', endISO).neq('wms_status','CANCELED')
    );
    // Map each order → its WIB month (1..12)
    const orderMonth = new Map();
    orders.forEach(o => {
      const d = new Date(o.transaction_date);
      if (isNaN(d)) return;
      const wib = new Date(d.getTime() + 7*3600000);   // shift to WIB, read in UTC
      orderMonth.set(o.salesorder_id, wib.getUTCMonth()+1);
    });
    const orderIds = orders.map(o => o.salesorder_id);
    fb.textContent = `${orders.length.toLocaleString('id-ID')} orders → mengambil items...`;

    // 2. Pull items for those orders, chunked
    const items = [];
    for (let i = 0; i < orderIds.length; i += 500) {
      const chunk = orderIds.slice(i, i+500);
      const rows = await _fetchAllPages(
        'jubelio_sales_order_items',
        'salesorder_id,item_id,item_name,qty,price,disc_amount,amount,is_canceled_item',
        q => q.in('salesorder_id', chunk)
      );
      items.push(...rows);
      fb.textContent = `${items.length.toLocaleString('id-ID')} items dimuat...`;
    }

    // 3. Product mappings → IP + parent item. Match primarily by jubelio_item_id
    //    (variant-level, matches sales item_id) with item_name as a fallback.
    //    The mapping's item_name IS the parent-item name.
    fb.textContent = `${items.length.toLocaleString('id-ID')} items → mapping ke IP...`;
    const mappings = await _fetchAllPages(
      'product_mappings',
      'jubelio_item_id,item_name,ip',
      q => q.not('ip','is',null)
    );
    const itemIdMap = new Map();   // jubelio_item_id → {ip, parent}
    const nameMap   = new Map();   // item_name → {ip, parent}
    mappings.forEach(m => {
      if (!m.ip) return;
      const info = { ip: m.ip, parent: (m.item_name||'').trim() || m.ip };
      if (m.jubelio_item_id != null) itemIdMap.set(String(m.jubelio_item_id), info);
      if (m.item_name) nameMap.set(m.item_name, info);
    });

    // 4. IP Master royalty config
    const {data: ipRows, error: ipErr} = await sb.from('ip_master')
      .select('id,name,category,royalty_type,percentage,fixed_amount,termin,pph_tax_rate,live_status');
    if (ipErr) throw ipErr;
    const ipByName = new Map();
    (ipRows||[]).forEach(r => ipByName.set((r.name||'').trim(), r));

    // 5. Aggregate per IP, tracking per-month and per-parent-item sub-totals
    const byIP = new Map();
    items.forEach(it => {
      if (it.is_canceled_item) return;
      const info = (it.item_id != null && itemIdMap.get(String(it.item_id))) || nameMap.get(it.item_name);
      if (!info) return;   // unmapped item, ignore for royalty calc
      const ipName = info.ip;
      const parent = info.parent || it.item_name || '—';
      const qty   = parseFloat(it.qty || 0) || 0;
      const gross = parseFloat(it.amount || 0) || (qty * (parseFloat(it.price||0)||0) - (parseFloat(it.disc_amount||0)||0));
      const mo = orderMonth.get(it.salesorder_id) || 0;
      if (!byIP.has(ipName)) byIP.set(ipName, { qty:0, gross:0, months:{}, parents:{} });
      const a = byIP.get(ipName);
      a.qty += qty; a.gross += gross;
      if (mo) { (a.months[mo] = a.months[mo] || {qty:0,gross:0}); a.months[mo].qty += qty; a.months[mo].gross += gross; }
      (a.parents[parent] = a.parents[parent] || {qty:0,gross:0}); a.parents[parent].qty += qty; a.parents[parent].gross += gross;
    });

    // 6. Compose rows + per-IP detail for drill-down
    _ryRows = []; _ryDetail = {};
    byIP.forEach((agg, ipName) => {
      const ip = ipByName.get(ipName) || {};
      const pct = parseFloat(ip.percentage||0) || 0;
      const fixedAmt = parseFloat(ip.fixed_amount||0) || 0;
      const royaltyType = (ip.royalty_type||'').trim() || (pct?'Post-Sales':(fixedAmt?'Advance':'—'));
      const pphRate = parseFloat(ip.pph_tax_rate||0) || 0;
      const royalty = (royaltyType === 'Advance') ? 0 : (agg.gross * pct / 100);
      const pphAmount = royalty * pphRate / 100;
      const net = royalty - pphAmount;
      _ryRows.push({
        ipId: ip.id || '', ipName, category: ip.category || '—', royaltyType,
        percentage: pct, fixedAmount: fixedAmt, termin: ip.termin || '—', pphRate,
        qty: agg.qty, gross: agg.gross, royalty, pphAmount, net,
        liveStatus: ip.live_status || '', inIpMaster: ipByName.has(ipName),
      });
      _ryDetail[ipName] = { months: agg.months, parents: agg.parents, pct, pphRate, royaltyType };
    });
    _ryRows.sort((a,b) => b.gross - a.gross);

    if (_ryMode === 'year') {
      // Per-IP tab: dropdown of IPs + inline breakdown for the selected one
      ryPopulateIPSelect();
      ryRenderSelectedIP();
      document.getElementById('ry-stats').style.display = 'none';
      document.getElementById('ry-result-wrap').style.display = 'none';
      document.getElementById('ry-result-ip').style.display = 'block';
    } else {
      // Per-bulan tab: all-IP table for the month
      ryRenderTable();
      document.getElementById('ry-stats').style.display = 'grid';
      document.getElementById('ry-result-wrap').style.display = 'block';
      document.getElementById('ry-result-ip').style.display = 'none';
    }
    fb.textContent = '';
  } catch(e) {
    console.error('loadRoyaltyReport:', e);
    fb.textContent = 'Error: ' + (e.message||e);
    fb.className = 'feedback err';
  } finally {
    btn.textContent = 'Load Data'; btn.disabled = false;
  }
}

// Per-IP detail: month + parent-item breakdown
let _ryDetail = {};

// Shared builder: returns {body, totQty, totGross, royalty, pphAmount, net, pct, pphRate, royaltyType}
function ryBuildBreakdown(ipName, withMonths) {
  const d = _ryDetail[ipName];
  if (!d) return null;
  const isAdvance = d.royaltyType === 'Advance';
  const royaltyOf = gross => isAdvance ? 0 : (gross * d.pct / 100);

  let totQty=0, totGross=0;
  Object.values(d.parents).forEach(p => { totQty+=p.qty; totGross+=p.gross; });
  const royalty = royaltyOf(totGross);
  const pphAmount = royalty * d.pphRate / 100;

  const thStyle = 'text-align:right;padding:7px 10px;font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:.04em;color:var(--g400);border-bottom:1px solid var(--g100)';
  const thLeft  = thStyle.replace('text-align:right','text-align:left');

  // Monthly breakdown (Jan–Dec)
  let monthRows = '';
  for (let m=1; m<=12; m++) {
    const mm = d.months[m]; const g = mm?mm.gross:0; const q = mm?mm.qty:0;
    const roy = royaltyOf(g);
    monthRows += `<tr style="${g?'':'opacity:.4'}">
      <td style="padding:6px 10px">${CAL_MONTH_NAMES[m-1]}</td>
      <td class="mono" style="text-align:right;padding:6px 10px">${new Intl.NumberFormat('id-ID').format(Math.round(q))}</td>
      <td class="mono" style="text-align:right;padding:6px 10px">${_ryRp(g)}</td>
      <td class="mono" style="text-align:right;padding:6px 10px;font-weight:600">${roy?_ryRp(roy):'—'}</td>
    </tr>`;
  }
  const monthBlock = withMonths ? `
    <div>
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:.05em;color:var(--g400);margin-bottom:8px">📅 Breakdown per Bulan</div>
      <table style="width:100%;border-collapse:collapse;font-size:12px">
        <thead><tr><th style="${thLeft}">Bulan</th><th style="${thStyle}">Qty</th><th style="${thStyle}">Gross</th><th style="${thStyle}">Royalty</th></tr></thead>
        <tbody>${monthRows}</tbody>
        <tfoot><tr style="font-weight:700;background:var(--off)">
          <td style="padding:7px 10px">Total</td>
          <td class="mono" style="text-align:right;padding:7px 10px">${new Intl.NumberFormat('id-ID').format(Math.round(totQty))}</td>
          <td class="mono" style="text-align:right;padding:7px 10px">${_ryRp(totGross)}</td>
          <td class="mono" style="text-align:right;padding:7px 10px">${_ryRp(royalty)}</td>
        </tr></tfoot>
      </table>
    </div>` : '';

  // Parent-item breakdown (sorted by gross desc)
  const parents = Object.entries(d.parents).map(([name,v]) => ({name, ...v})).sort((a,b)=>b.gross-a.gross);
  const parentRows = parents.map(p => `<tr>
      <td style="padding:6px 10px">${_ryEsc(p.name)}</td>
      <td class="mono" style="text-align:right;padding:6px 10px">${new Intl.NumberFormat('id-ID').format(Math.round(p.qty))}</td>
      <td class="mono" style="text-align:right;padding:6px 10px">${_ryRp(p.gross)}</td>
      <td class="mono" style="text-align:right;padding:6px 10px;font-weight:600">${royaltyOf(p.gross)?_ryRp(royaltyOf(p.gross)):'—'}</td>
    </tr>`).join('');
  const parentBlock = `
    <div>
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:.05em;color:var(--g400);margin-bottom:8px">📦 Breakdown per Parent Item (${parents.length})</div>
      <table style="width:100%;border-collapse:collapse;font-size:12px">
        <thead><tr><th style="${thLeft}">Parent Item</th><th style="${thStyle}">Qty</th><th style="${thStyle}">Gross</th><th style="${thStyle}">Royalty</th></tr></thead>
        <tbody>${parentRows || `<tr><td colspan="4" style="padding:16px;text-align:center;color:var(--g400)">—</td></tr>`}</tbody>
      </table>
    </div>`;

  const body = withMonths
    ? `<div style="display:grid;grid-template-columns:1fr 1.3fr;gap:24px;align-items:start">${monthBlock}${parentBlock}</div>`
    : parentBlock;

  return { body, totQty, totGross, royalty, pphAmount, net: royalty-pphAmount, pct:d.pct, pphRate:d.pphRate };
}

// Month-tab: click an IP row → modal with parent breakdown for that month
function openRyDetail(ipNameEnc) {
  const ipName = decodeURIComponent(ipNameEnc);
  const r = ryBuildBreakdown(ipName, false);
  if (!r) return;
  document.getElementById('ry-d-title').textContent = ipName;
  document.getElementById('ry-d-sub').innerHTML =
    `${_ryPeriod} · ${r.pct?r.pct.toFixed(2)+'% royalty':'—'}${r.pphRate?` · PPh ${r.pphRate.toFixed(2)}%`:''} · `
    + `Gross ${_ryRp(r.totGross)} · Royalty ${_ryRp(r.royalty)}`;
  document.getElementById('ry-d-body').innerHTML = r.body;
  document.getElementById('ry-detail-overlay').style.display = 'flex';
}

function closeRyDetail() {
  document.getElementById('ry-detail-overlay').style.display = 'none';
}

// Per-IP tab: populate IP dropdown (IPs with sales, sorted by gross) after a year load
function ryPopulateIPSelect() {
  const sel = document.getElementById('ry-ip-select');
  if (!sel) return;
  const grossOf = n => (_ryRows.find(r=>r.ipName===n)||{}).gross || 0;
  const names = Object.keys(_ryDetail).sort((a,b) => grossOf(b)-grossOf(a));
  const cur = sel.value;
  sel.innerHTML = names.length
    ? names.map(n => `<option value="${n.replace(/"/g,'&quot;')}"${n===cur?' selected':''}>${n.replace(/</g,'&lt;')}</option>`).join('')
    : `<option value="">(tidak ada IP dengan sales)</option>`;
  if (names.length && !names.includes(cur)) sel.value = names[0];
}

// Per-IP tab: render the selected IP's breakdown inline (with month table)
function ryRenderSelectedIP() {
  const box = document.getElementById('ry-result-ip');
  const ipName = document.getElementById('ry-ip-select')?.value;
  if (!ipName || !_ryDetail[ipName]) {
    box.innerHTML = `<div class="empty-td" style="padding:32px;text-align:center;color:var(--g400);font-size:12px">Tidak ada data. Pilih tahun lalu klik Load Data.</div>`;
    return;
  }
  const r = ryBuildBreakdown(ipName, true);
  const ipRow = _ryRows.find(x => x.ipName === ipName) || {};
  const stat = (label,val,extra='') => `<div class="stat-card" style="${extra}"><div class="stat-num">${val}</div><div class="stat-lbl">${label}</div></div>`;
  box.innerHTML = `
    <div style="display:flex;align-items:baseline;gap:10px;margin-bottom:12px;flex-wrap:wrap">
      <div style="font-family:var(--head);font-size:18px;font-weight:700">${_ryEsc(ipName)}</div>
      <div style="font-size:12px;color:var(--g400)">${_ryPeriod} · ${ipRow.category||'—'} · ${r.pct?r.pct.toFixed(2)+'% royalty':'—'}${r.pphRate?` · PPh ${r.pphRate.toFixed(2)}%`:''}</div>
    </div>
    <div class="stats-row" style="grid-template-columns:repeat(5,1fr);margin-bottom:1.25rem">
      ${stat('Qty Terjual', new Intl.NumberFormat('id-ID').format(Math.round(r.totQty)))}
      ${stat('Gross Sales', _ryRp(r.totGross))}
      ${stat('Royalty', _ryRp(r.royalty))}
      ${stat('PPh', r.pphAmount?'-'+_ryRp(r.pphAmount):'Rp 0')}
      ${stat('Net Royalty', _ryRp(r.net))}
    </div>
    ${r.body}`;
}

function ryRenderTable() {
  const search = (document.getElementById('ry-search')?.value || '').trim().toLowerCase();
  const typeFil = document.getElementById('ry-fil-type')?.value || '';
  const rows = _ryRows.filter(r => {
    if (search && !r.ipName.toLowerCase().includes(search)) return false;
    if (typeFil && r.royaltyType !== typeFil) return false;
    return true;
  });

  // Aggregate stats from filtered rows (so filter reshapes the totals)
  let totQty = 0, totGross = 0, totRoyalty = 0, totPph = 0, totNet = 0;
  rows.forEach(r => { totQty+=r.qty; totGross+=r.gross; totRoyalty+=r.royalty; totPph+=r.pphAmount; totNet+=r.net; });

  document.getElementById('ry-s-ips').textContent     = rows.length;
  document.getElementById('ry-s-qty').textContent     = new Intl.NumberFormat('id-ID').format(Math.round(totQty));
  document.getElementById('ry-s-gross').textContent   = _ryRp(totGross);
  document.getElementById('ry-s-royalty').textContent = _ryRp(totRoyalty);
  document.getElementById('ry-s-net').textContent     = _ryRp(totNet);
  document.getElementById('ry-tcount').textContent    = `${rows.length} IP${typeFil?` · ${typeFil}`:''}`;

  const tb = document.getElementById('ry-tbody');
  if (!rows.length) {
    tb.innerHTML = `<tr><td colspan="11" class="empty-td" style="padding:32px;text-align:center;color:var(--g400);font-size:12px">${_ryRows.length?'Tidak ada IP cocok filter.':'Tidak ada sales yang ter-mapping ke IP di periode ini.'}</td></tr>`;
    document.getElementById('ry-tfoot').innerHTML = '';
    return;
  }

  tb.innerHTML = rows.map(r => {
    const typeClass = r.royaltyType==='Post-Sales'?'p-active':r.royaltyType==='Advance'?'p-signings':r.royaltyType==='Both'?'p-review':'p-inactive';
    const missing = !r.inIpMaster
      ? `<span style="color:#c0392b;font-size:10px;margin-left:6px" title="IP tidak ditemukan di IP Master">⚠</span>`
      : '';
    return `<tr onclick="openRyDetail('${encodeURIComponent(r.ipName)}')" style="cursor:pointer" onmouseover="this.style.background='var(--off)'" onmouseout="this.style.background=''" title="Klik untuk breakdown per bulan & parent item">
      <td style="font-weight:600">${_ryEsc(r.ipName)}${missing} <span style="color:var(--g300);font-size:10px">▸</span></td>
      <td><span class="pill p-draft" style="font-size:10px">${_ryEsc(r.category)}</span></td>
      <td>${r.royaltyType?`<span class="pill ${typeClass}" style="font-size:10px">${_ryEsc(r.royaltyType)}</span>`:'—'}</td>
      <td class="mono" style="text-align:right">${r.percentage?r.percentage.toFixed(2)+'%':'—'}</td>
      <td style="font-size:11px;color:var(--g600)">${_ryEsc(r.termin)}</td>
      <td class="mono" style="text-align:right;border-left:2px solid var(--g100)">${new Intl.NumberFormat('id-ID').format(Math.round(r.qty))}</td>
      <td class="mono" style="text-align:right">${_ryRp(r.gross)}</td>
      <td class="mono" style="text-align:right;border-left:2px solid var(--g100);font-weight:600">${r.royalty?_ryRp(r.royalty):'—'}</td>
      <td class="mono" style="text-align:right">${r.pphRate?r.pphRate.toFixed(2)+'%':'—'}</td>
      <td class="mono" style="text-align:right;color:#c0392b">${r.pphAmount?'-'+_ryRp(r.pphAmount):'—'}</td>
      <td class="mono" style="text-align:right;font-weight:700">${r.net?_ryRp(r.net):'—'}</td>
    </tr>`;
  }).join('');

  document.getElementById('ry-tfoot').innerHTML = `<tr>
    <td colspan="5" style="padding:10px;font-family:var(--mono);font-size:11px;text-transform:uppercase;letter-spacing:0.5px;color:var(--g600)">Total (${rows.length} IP)</td>
    <td class="mono" style="text-align:right;border-left:2px solid var(--g100)">${new Intl.NumberFormat('id-ID').format(Math.round(totQty))}</td>
    <td class="mono" style="text-align:right">${_ryRp(totGross)}</td>
    <td class="mono" style="text-align:right;border-left:2px solid var(--g100)">${_ryRp(totRoyalty)}</td>
    <td></td>
    <td class="mono" style="text-align:right;color:#c0392b">${totPph?'-'+_ryRp(totPph):'—'}</td>
    <td class="mono" style="text-align:right;font-weight:700">${_ryRp(totNet)}</td>
  </tr>`;
}

function downloadRoyaltyCSV() {
  if (!_ryRows.length) { alert('Load data dulu.'); return; }
  const search = (document.getElementById('ry-search')?.value || '').trim().toLowerCase();
  const typeFil = document.getElementById('ry-fil-type')?.value || '';
  const rows = _ryRows.filter(r => {
    if (search && !r.ipName.toLowerCase().includes(search)) return false;
    if (typeFil && r.royaltyType !== typeFil) return false;
    return true;
  });
  const esc = s => {
    if (s===null||s===undefined) return '';
    const t = String(s);
    return /[",\n\r]/.test(t) ? '"'+t.replace(/"/g,'""')+'"' : t;
  };
  const headers = ['IP','Category','Royalty Type','% Royalty','Termin','Qty','Gross Sales (Rp)','Royalty (Rp)','PPh %','PPh (Rp)','Net Royalty (Rp)'];
  const lines = [headers.map(esc).join(',')];
  rows.forEach(r => {
    lines.push([
      r.ipName, r.category, r.royaltyType,
      r.percentage||'', r.termin,
      Math.round(r.qty), Math.round(r.gross),
      Math.round(r.royalty), r.pphRate||'',
      Math.round(r.pphAmount), Math.round(r.net)
    ].map(esc).join(','));
  });
  const blob = new Blob([lines.join('\r\n')], {type:'text/csv;charset=utf-8;'});
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = `royalty-report-${_ryPeriod}.csv`;
  a.click();
  URL.revokeObjectURL(a.href);
}

// ── DUPLICATE CHECK ──
async function checkDuplicate(name, excludeSheet) {
  // Check IP Master and Brand Master for duplicate name
  const ipNames = allIPRows.map(r=>(r.name||"").toLowerCase().trim());
  const bmNames = allBMRows.map(r=>(r.name||"").toLowerCase().trim());
  const n = name.toLowerCase().trim();
  if (excludeSheet !== "ip"  && ipNames.includes(n)) return "IP Master";
  if (excludeSheet !== "bm"  && bmNames.includes(n)) return "Brand Master";
  return null;
}

// ── SESSION RESTORE ──
(async () => {
  // Check for password recovery token in URL hash (#access_token=...&type=recovery)
  const hash = Object.fromEntries(new URLSearchParams(location.hash.slice(1)));
  if (hash.type === "recovery" && hash.access_token) {
    // Set the session from the recovery token so updateUser() works
    await sb.auth.setSession({ access_token: hash.access_token, refresh_token: hash.refresh_token || "" });
    history.replaceState(null, "", location.pathname); // clean up URL
    document.getElementById("loginBox").style.display = "none";
    document.getElementById("resetBox").style.display = "block";
    return;
  }
  // Normal session restore
  const { data: { session } } = await sb.auth.getSession();
  if (session?.user) enterApp(session.user);
})();

async function doResetPassword() {
  const p1  = document.getElementById("resetPass1").value;
  const p2  = document.getElementById("resetPass2").value;
  const err = document.getElementById("resetErr");
  const btn = document.getElementById("resetBtn");
  if (!p1 || p1.length < 8) { err.textContent = "Password minimal 8 karakter."; return; }
  if (p1 !== p2)             { err.textContent = "Password tidak cocok."; return; }
  err.textContent = "";
  btn.disabled = true; btn.textContent = "Menyimpan...";
  const { error } = await sb.auth.updateUser({ password: p1 });
  if (error) { err.textContent = "Gagal: " + error.message; btn.disabled = false; btn.textContent = "Simpan Password →"; return; }
  // Password saved — sign in automatically
  const { data: { session } } = await sb.auth.getSession();
  if (session?.user) { enterApp(session.user); return; }
  // Fallback: show login
  document.getElementById("resetBox").style.display = "none";
  document.getElementById("loginBox").style.display = "block";
  document.getElementById("loginErr").textContent = "Password berhasil diubah. Silakan login.";
}

// ─── NEED RESTOCK MODULE ──────────────────────────────────────────────────────

const RESTOCK_BRANDS    = ['SD&Y', 'Lagaa', 'Marte'];
const RESTOCK_LEAD_DAYS = 30;   // flag variant if days_of_stock < this
const RESTOCK_TARGET    = 60;   // suggested order covers this many days

let _rstLoading       = false;
let _rstData          = null;     // { products, dayCount }
let _rstExpanded      = {};       // parentName → bool
let _rstSelectedItems = new Set();// item_ids ticked for PO
let _rstMode          = 'restock'; // 'restock' | 'catalog'

function _rstParseSize(itemCode) {
  if (!itemCode) return '—';
  const parts = itemCode.split('---');
  const last  = parts[parts.length - 1];
  const segs  = last.split('-');
  const raw   = segs[segs.length - 1];
  const SIZES = ['XS','S','M','L','XL','XXL','XXXL','4XL','5XL'];
  if (SIZES.includes(raw)) return raw;
  return raw.charAt(0).toUpperCase() + raw.slice(1).toLowerCase();
}

async function loadRestock() {
  if (_rstLoading) return;
  _rstLoading = true;
  const tbody = document.getElementById('rst-tbody');
  if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">⟳ Memuat data...</td></tr>`;
  ['rst-s-skus','rst-s-products','rst-s-suggested'].forEach(id => { const e=document.getElementById(id); if(e) e.textContent='—'; });

  try {
    const fromDate = document.getElementById('rst-from')?.value;
    const toDate   = document.getElementById('rst-to')?.value;
    if (!fromDate || !toDate) {
      if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Pilih periode terlebih dahulu.</td></tr>`;
      return;
    }
    const dayCount  = Math.max(1, Math.round((new Date(toDate)-new Date(fromDate))/864e5)+1);
    const brandFil  = document.getElementById('rst-brand')?.value || '';
    const brands    = brandFil ? [brandFil] : RESTOCK_BRANDS;

    // 1. Product mappings for target brands
    const mappings = await _fetchAllPages('product_mappings','jubelio_item_id,item_name,brand,ip,collection',
      q => q.in('brand', brands).not('jubelio_item_id','is',null));
    if (!mappings.length) {
      if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Tidak ada produk untuk brand yang dipilih.</td></tr>`;
      return;
    }
    const allItemIds  = [...new Set(mappings.map(m => m.jubelio_item_id))];
    const mappingById = {};
    for (const m of mappings) mappingById[m.jubelio_item_id] = m;

    // 2. COMPLETED orders in date range (IDs only)
    const orders = await _fetchAllPages('jubelio_sales_orders','salesorder_id',
      q => q.eq('wms_status','COMPLETED')
            .gte('transaction_date', fromDate+'T00:00:00')
            .lte('transaction_date', toDate+'T23:59:59'));
    const orderIds = orders.map(o => o.salesorder_id);

    // 3-5. Parallel: sold items (filter by item only — orderIdSet applied client-side),
    //      stock, item info
    const orderIdSet = new Set(orderIds);
    const [soldItemsRaw, stockRows, itemInfoRows] = await Promise.all([
      allItemIds.length
        ? _fetchAllPages('jubelio_sales_order_items','salesorder_id,item_id,qty',
            q => q.in('item_id', allItemIds))
        : Promise.resolve([]),
      _fetchAllPages('jubelio_inventory_stocks','item_id,on_hand',
        q => q.in('item_id', allItemIds)),
      _fetchAllPages('jubelio_items','item_id,item_code,item_name,thumbnail',
        q => q.in('item_id', allItemIds)),
    ]);
    // Client-side: only count qty from orders in the selected period
    const soldItems = soldItemsRaw.filter(it => orderIdSet.has(it.salesorder_id));

    // Build lookups
    const qtyMap   = {};
    for (const it of soldItems) qtyMap[it.item_id] = (qtyMap[it.item_id]||0) + parseFloat(it.qty||0);
    const stockMap = {};
    for (const r of stockRows) stockMap[r.item_id] = (stockMap[r.item_id]||0) + parseFloat(r.on_hand||0);
    const infoMap  = {};
    for (const r of itemInfoRows) infoMap[r.item_id] = r;

    // Group by parent name
    const productMap = {};
    for (const m of mappings) {
      const { item_name: parentName, brand, ip, collection, jubelio_item_id: itemId } = m;
      if (!productMap[parentName]) productMap[parentName] = { name:parentName, brand, ip, collection:collection||'', thumbnail:null, variants:[] };
      const info        = infoMap[itemId]  || {};
      const stock       = stockMap[itemId] || 0;
      const qtySold     = qtyMap[itemId]   || 0;
      const avgDaily    = qtySold / dayCount;
      const daysOfStock = avgDaily > 0 ? stock / avgDaily : null;
      const suggestedQty= avgDaily > 0 ? Math.max(0, Math.ceil(RESTOCK_TARGET * avgDaily) - stock) : 0;
      const needsRestock= daysOfStock !== null && daysOfStock < RESTOCK_LEAD_DAYS;
      if (!productMap[parentName].thumbnail && info.thumbnail) productMap[parentName].thumbnail = info.thumbnail;
      productMap[parentName].variants.push({
        itemId, itemCode: info.item_code||'', itemNameFull: info.item_name||parentName,
        size: _rstParseSize(info.item_code),
        stock, qtySold, avgDaily, daysOfStock, suggestedQty, needsRestock,
      });
    }

    // Sort variants by size order
    const _SO = ['XS','S','M','L','XL','XXL','XXXL','4XL','5XL'];
    for (const p of Object.values(productMap)) {
      p.variants.sort((a,b) => { const ai=_SO.indexOf(a.size), bi=_SO.indexOf(b.size); if(ai>=0&&bi>=0)return ai-bi; if(ai>=0)return -1; if(bi>=0)return 1; return a.size.localeCompare(b.size); });
      p.restockCount = p.variants.filter(v => v.needsRestock).length;
      p.minDays      = p.variants.filter(v => v.daysOfStock!==null).reduce((m,v) => Math.min(m,v.daysOfStock), Infinity);
      if (p.minDays===Infinity) p.minDays=null;
    }

    // Sort products: urgent first, then by minDays, then name
    const products = Object.values(productMap).sort((a,b) => {
      if (a.restockCount>0 && b.restockCount===0) return -1;
      if (a.restockCount===0 && b.restockCount>0) return  1;
      if (a.minDays!==null && b.minDays!==null) return a.minDays-b.minDays;
      return a.name.localeCompare(b.name);
    });

    _rstData = { products, dayCount };

    // Populate IP and collection dropdowns
    const _populateDrop = (id, vals) => {
      const el = document.getElementById(id); if (!el) return;
      const cur = el.value;
      el.innerHTML = `<option value="">${id==='rst-ip'?'Semua IP':'Semua Collection'}</option>`
        + vals.map(v => `<option value="${v}"${v===cur?' selected':''}>${v}</option>`).join('');
    };
    _populateDrop('rst-ip',         [...new Set(products.map(p=>p.ip).filter(Boolean))].sort());
    _populateDrop('rst-collection',  [...new Set(products.map(p=>p.collection).filter(Boolean))].sort());

    // Auto-expand products with restock needs, pre-check urgent variants
    for (const p of products) {
      if (_rstExpanded[p.name]===undefined) _rstExpanded[p.name] = p.restockCount>0;
    }
    if (_rstSelectedItems.size===0) {
      for (const p of products)
        for (const v of p.variants)
          if (v.needsRestock && v.suggestedQty>0) _rstSelectedItems.add(v.itemId);
    }

    renderRestockTable(products);

    // Stats
    const rstSkus  = products.reduce((s,p) => s+p.restockCount, 0);
    const rstProds = products.filter(p => p.variants.some(v => v.qtySold>0)).length;
    const rstSugg  = products.reduce((s,p) => s+p.variants.filter(v=>v.needsRestock).reduce((ss,v)=>ss+v.suggestedQty,0), 0);
    const _se = (id,v) => { const e=document.getElementById(id); if(e)e.textContent=v; };
    _se('rst-s-skus',     rstSkus.toLocaleString('id-ID'));
    _se('rst-s-products', rstProds.toLocaleString('id-ID'));
    _se('rst-s-suggested',rstSugg.toLocaleString('id-ID')+' unit');
    _rstUpdateSelected();

  } catch(e) {
    console.error('loadRestock:',e);
    if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9" style="color:#c0392b">Error: ${e.message}</td></tr>`;
  } finally {
    _rstLoading = false;
  }
}

function renderRestockTable(products) {
  const tbody      = document.getElementById('rst-tbody');
  const showAll    = document.getElementById('rst-show-all')?.checked;
  const isCatalog  = _rstMode === 'catalog';
  if (!tbody) return;

  const ipFil     = document.getElementById('rst-ip')?.value         || '';
  const colFil    = document.getElementById('rst-collection')?.value  || '';
  const brandFil2 = document.getElementById('rst-brand')?.value       || '';
  const searchTerm= (document.getElementById('rst-search')?.value     || '').toLowerCase().trim();

  const RST_ROLL      = 60;
  const RST_THRESHOLD = Math.round(RST_ROLL * 0.75); // 45 — min qty to justify a reorder

  const rows = [];
  let totalVisible = 0;

  for (const p of products) {
    const hasRestock = p.restockCount > 0;
    // Mode filter: in 'restock' mode hide products with no restock need (unless showAll)
    if (!isCatalog && !showAll && !hasRestock) continue;
    if (brandFil2  && p.brand !== brandFil2)              continue;
    if (ipFil      && p.ip !== ipFil)                     continue;
    if (colFil     && p.collection !== colFil)            continue;
    if (searchTerm && !p.name.toLowerCase().includes(searchTerm)) continue;

    const pKey     = btoa(unescape(encodeURIComponent(p.name))).replace(/[^a-zA-Z0-9]/g,'');
    const expanded = !!_rstExpanded[p.name];

    // Urgency badge
    let urgBadge = '';
    if (p.minDays!==null && p.minDays<RESTOCK_LEAD_DAYS) {
      const clr = p.minDays<7 ? '#c0392b' : p.minDays<14 ? '#e65100' : '#b8860b';
      const bg  = p.minDays<7 ? '#fdf0f0' : p.minDays<14 ? '#fff3e0' : '#fffde7';
      const bdr = p.minDays<7 ? '#e8b8b8' : p.minDays<14 ? '#ffb74d' : '#ffe082';
      urgBadge  = `<span style="font-size:9px;background:${bg};color:${clr};border:1px solid ${bdr};border-radius:3px;padding:1px 5px;font-family:var(--mono);white-space:nowrap">⚠ ${Math.floor(p.minDays)}d</span>`;
    }

    const thumb = p.thumbnail
      ? `<img src="${p.thumbnail}" style="width:28px;height:28px;object-fit:cover;border-radius:3px;border:1px solid var(--g100);flex-shrink:0">`
      : `<div style="width:28px;height:28px;background:var(--g50);border-radius:3px;border:1px solid var(--g100);flex-shrink:0"></div>`;

    const allUrgChk = _rstAllVariantsChecked(p);

    // Auto-suggest qty per variant using roll rounding logic
    // rawTotal = sum of all variants' suggestedQty (restock-needed variants)
    const restockVars = p.variants.filter(v => v.suggestedQty > 0);
    const rawTotal    = restockVars.reduce((s, v) => s + v.suggestedQty, 0);
    const adjQtys     = {}; // itemId → adjusted qty
    if (rawTotal >= RST_THRESHOLD) {
      // At or above threshold: round up to nearest multiple of RST_ROLL
      const roundedTotal = Math.ceil(rawTotal / RST_ROLL) * RST_ROLL;
      // Distribute proportionally, fix rounding remainder on largest variant
      let distSum = 0;
      restockVars.forEach(v => { adjQtys[v.itemId] = Math.floor(v.suggestedQty / rawTotal * roundedTotal); distSum += adjQtys[v.itemId]; });
      const rem = roundedTotal - distSum;
      if (rem > 0) {
        const largest = restockVars.reduce((a, b) => b.suggestedQty > a.suggestedQty ? b : a);
        adjQtys[largest.itemId] = (adjQtys[largest.itemId] || 0) + rem;
      }
    }
    // Below threshold: adjQtys stays empty → product shown as "belum layak reorder"

    rows.push(`<tr class="rst-product-row" style="background:#f7f8fa;border-top:2px solid var(--g200);cursor:pointer" onclick="_rstToggleExpand('${pKey}','${p.name.replace(/'/g,"\\'")}')">`+
      `<td style="padding:7px 8px;text-align:center"><span style="font-size:10px;color:var(--g400)">${expanded?'▼':'▶'}</span></td>`+
      `<td style="padding:7px 4px;text-align:center"><input type="checkbox" class="rst-prod-chk" data-pkey="${pKey}" ${allUrgChk?'checked':''} onclick="event.stopPropagation();_rstToggleProduct('${pKey}','${p.name.replace(/'/g,"\\'").replace(/"/g,'&quot;')}',this.checked)" style="cursor:pointer"></td>`+
      `<td style="padding:7px 8px" colspan="6"><div style="display:flex;align-items:center;gap:8px">${thumb}<div>`+
      `<div style="font-size:13px;font-weight:600;color:var(--text)">${p.name}</div>`+
      `<div style="display:flex;gap:6px;align-items:center;margin-top:2px">`+
      `<span style="font-size:10px;color:var(--g400)">${p.brand}</span>`+
      (p.ip ? `<span style="font-size:10px;color:var(--g300)">·</span><span style="font-size:10px;color:var(--g400)">${p.ip}</span>` : '')+
      (urgBadge ? ' '+urgBadge : '')+
      (hasRestock ? `<span style="font-size:10px;color:var(--g400)">${p.restockCount} SKU perlu restock</span>` : `<span style="font-size:10px;color:#2d7a2d">✓ stok aman</span>`)+
      `</div></div></div></td>`+
      `<td style="padding:7px 8px;text-align:right;font-size:10px;color:var(--g300)">Harga Beli</td>`+
      `</tr>`);

    totalVisible++;

    if (!expanded && !isCatalog) continue;

    for (const v of p.variants) {
      // In restock mode (non-showAll): skip safe-stock variants; in catalog mode: show all
      if (!isCatalog && !showAll && !v.needsRestock) continue;
      const chk = _rstSelectedItems.has(v.itemId);
      const dClr= v.daysOfStock===null ? '#aaa' : v.daysOfStock<7 ? '#c0392b' : v.daysOfStock<14 ? '#e65100' : v.daysOfStock<30 ? '#b8860b' : '#2d7a2d';
      const dStr= v.daysOfStock!==null ? Math.floor(v.daysOfStock)+'d' : '—';
      const aStr= v.avgDaily>0 ? v.avgDaily.toFixed(1) : '—';
      const P   = 'padding:5px 8px;vertical-align:middle';
      const safeItemName = (v.itemNameFull||'').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
      rows.push(`<tr class="rst-variant-row" style="border-bottom:1px solid var(--g50);${chk?'background:#f0f7ff':''}">`+
        `<td style="${P}"></td>`+
        `<td style="${P};text-align:center"><input type="checkbox" class="rst-var-chk" data-item-id="${v.itemId}" data-item-code="${v.itemCode}" data-item-name="${safeItemName}" data-pkey="${pKey}" ${chk?'checked':''} onchange="_rstToggleVariant(${v.itemId},this.checked,'${pKey}')" style="cursor:pointer"></td>`+
        `<td style="${P};font-size:12px;color:var(--text);font-weight:${v.needsRestock?600:400}">${v.size}</td>`+
        `<td style="${P};text-align:right;font-size:12px;font-family:var(--mono)">${v.stock}</td>`+
        `<td style="${P};text-align:right;font-size:12px;font-family:var(--mono);color:var(--g400)">${v.qtySold>0?v.qtySold:'—'}</td>`+
        `<td style="${P};text-align:right;font-size:12px;font-family:var(--mono);color:var(--g400)">${aStr}</td>`+
        `<td style="${P};text-align:right;font-size:12px;font-family:var(--mono);color:${dClr};font-weight:${v.needsRestock?700:400}">${dStr}</td>`+
        `<td style="${P};text-align:right"><input type="number" class="rst-qty-input" min="0" step="1" value="${chk&&(adjQtys[v.itemId]||v.suggestedQty)>0?(adjQtys[v.itemId]||v.suggestedQty):''}" placeholder="0" style="width:70px;text-align:right;font-size:12px;font-family:var(--mono);padding:3px 6px;border:1px solid var(--g200);border-radius:4px;background:white"></td>`+
        `<td style="${P};text-align:right"><input type="number" class="rst-price-input" min="0" step="1000" placeholder="0" style="width:90px;text-align:right;font-size:12px;font-family:var(--mono);padding:3px 6px;border:1px solid var(--g200);border-radius:4px;background:white"></td>`+
        `</tr>`);
    }
  }

  tbody.innerHTML = rows.join('') || `<tr><td class="empty-td" colspan="9">Tidak ada produk yang perlu restock dalam periode ini.</td></tr>`;
  const tc = document.getElementById('rst-tcount');
  if (tc) tc.textContent = `${totalVisible} produk`;
}

function _rstToggleExpand(pKey, pName) {
  _rstExpanded[pName] = !_rstExpanded[pName];
  if (_rstData) renderRestockTable(_rstData.products);
}

function _rstAllVariantsChecked(product) {
  const urgent = product.variants.filter(v => v.needsRestock);
  return urgent.length>0 && urgent.every(v => _rstSelectedItems.has(v.itemId));
}

function _rstToggleProduct(pKey, pName, checked) {
  if (!_rstData) return;
  const p = _rstData.products.find(pp => pp.name===pName);
  if (!p) return;
  for (const v of p.variants) {
    if (checked) { if (v.needsRestock) _rstSelectedItems.add(v.itemId); }
    else          _rstSelectedItems.delete(v.itemId);
  }
  renderRestockTable(_rstData.products);
  _rstUpdateSelected();
}

function _rstToggleVariant(itemId, checked, pKey) {
  if (checked) _rstSelectedItems.add(itemId);
  else         _rstSelectedItems.delete(itemId);
  // sync product-level checkbox
  if (_rstData) {
    const p = _rstData.products.find(pp =>
      btoa(unescape(encodeURIComponent(pp.name))).replace(/[^a-zA-Z0-9]/g,'') === pKey);
    if (p) {
      const prodChk = document.querySelector(`.rst-prod-chk[data-pkey="${pKey}"]`);
      if (prodChk) prodChk.checked = _rstAllVariantsChecked(p);
    }
  }
  const row = document.querySelector(`.rst-var-chk[data-item-id="${itemId}"]`)?.closest('tr');
  if (row) row.style.background = checked ? '#f0f7ff' : '';
  _rstUpdateSelected();
}

function rstToggleAll(checked) {
  const _ROLL = 60, _THR = Math.round(60 * 0.75);
  _rstSelectedItems.clear();
  if (checked && _rstData) {
    for (const p of _rstData.products) {
      const rawTotal = p.variants.filter(v => v.suggestedQty > 0).reduce((s,v) => s + v.suggestedQty, 0);
      if (rawTotal >= _THR)
        for (const v of p.variants)
          if (v.needsRestock) _rstSelectedItems.add(v.itemId);
    }
  }
  if (_rstData) renderRestockTable(_rstData.products);
  _rstUpdateSelected();
}

function _rstUpdateSelected() {
  const e = document.getElementById('rst-s-selected');
  if (e) e.textContent = _rstSelectedItems.size;
}

function _rstUpdateProductTotal(pKey) {
  const RST_ROLL = 60;
  let total = 0;
  document.querySelectorAll(`.rst-var-chk[data-pkey="${pKey}"]:checked`).forEach(chk => {
    const qty = parseFloat(chk.closest('tr')?.querySelector('.rst-qty-input')?.value) || 0;
    total += qty;
  });
  const totalEl = document.getElementById(`rst-ptotal-${pKey}`);
  const validEl = document.getElementById(`rst-pvalid-${pKey}`);
  if (totalEl) totalEl.textContent = total > 0 ? total : '—';
  if (validEl) {
    if (total <= 0) {
      validEl.innerHTML = '';
    } else if (total % RST_ROLL === 0) {
      validEl.innerHTML = `<span style="color:#2d7a2d;font-size:10px;font-family:var(--mono)">✓ ${total/RST_ROLL} roll</span>`;
    } else {
      const next = Math.ceil(total/RST_ROLL)*RST_ROLL;
      validEl.innerHTML = `<span style="color:#e65100;font-size:10px;font-family:var(--mono)">⚠ next: ${next}</span>`;
    }
  }
}

function _rstSetMode(mode) {
  _rstMode = mode;
  const rb = document.getElementById('rst-mode-restock');
  const cb = document.getElementById('rst-mode-catalog');
  if (rb) { rb.style.background = mode==='restock'?'#3C3489':'white'; rb.style.color = mode==='restock'?'white':'var(--g400)'; }
  if (cb) { cb.style.background = mode==='catalog'?'#3C3489':'white'; cb.style.color = mode==='catalog'?'white':'var(--g400)'; }
  if (_rstData) renderRestockTable(_rstData.products);
}

function generateRestockPO() {
  const supplierEl = document.getElementById('rst-supplier');
  if (!supplierEl?.value) { alert('Pilih supplier terlebih dahulu.'); return; }
  _rstShowSummary();
}

function _rstShowSummary() {
  const supplierEl   = document.getElementById('rst-supplier');
  const supplierName = supplierEl?.options[supplierEl.selectedIndex]?.text || 'MGMT';

  const productSummary = {};
  let hasZeroPrice = false;

  document.querySelectorAll('.rst-var-chk:checked').forEach(chk => {
    const row   = chk.closest('tr');
    const qty   = parseFloat(row?.querySelector('.rst-qty-input')?.value)   || 0;
    const price = parseFloat(row?.querySelector('.rst-price-input')?.value) || 0;
    if (qty <= 0) return;
    if (price === 0) hasZeroPrice = true;

    const pKey = chk.dataset.pkey;
    let parentName = '', brand = '', ip = '', collection = '', size = '?';
    if (_rstData) {
      const p = _rstData.products.find(pp =>
        btoa(unescape(encodeURIComponent(pp.name))).replace(/[^a-zA-Z0-9]/g,'') === pKey);
      if (p) {
        parentName = p.name; brand = p.brand; ip = p.ip||''; collection = p.collection||'';
        const v = p.variants.find(vv => vv.itemId === Number(chk.dataset.itemId));
        if (v) size = v.size;
      }
    }
    if (!parentName) parentName = chk.dataset.itemCode || '—';

    if (!productSummary[parentName]) {
      productSummary[parentName] = { name:parentName, brand, ip, collection, pKey, roll:60, sizeQtys:{}, prices:[], totalQty:0, totalNilai:0 };
    }
    productSummary[parentName].sizeQtys[size] = qty;
    productSummary[parentName].prices.push(price);
    productSummary[parentName].totalQty   += qty;
    productSummary[parentName].totalNilai += qty * price;
  });

  if (!Object.keys(productSummary).length) {
    alert('Tidak ada item dipilih atau semua qty = 0.');
    return;
  }

  // Collect sizes in standard order
  const _SO = ['XS','S','M','L','XL','XXL','XXXL','4XL','5XL'];
  const sizeSet = new Set();
  for (const p of Object.values(productSummary)) for (const s of Object.keys(p.sizeQtys)) sizeSet.add(s);
  const sizes = [..._SO.filter(s => sizeSet.has(s)), ...[...sizeSet].filter(s => !_SO.includes(s)).sort()];

  const prods      = Object.values(productSummary);
  const grandQty   = prods.reduce((s,p) => s + p.totalQty,   0);
  const grandNilai = prods.reduce((s,p) => s + p.totalNilai, 0);
  const fmtRp = v => 'Rp ' + Math.round(v).toLocaleString('id-ID');

  let html = `<div style="font-size:12px;color:var(--g400);margin-bottom:12px">
    Supplier: <strong style="color:var(--text)">${supplierName}</strong>
    &nbsp;·&nbsp; ${prods.length} produk &nbsp;·&nbsp; ${grandQty} unit
    ${grandNilai > 0 ? '&nbsp;·&nbsp; <strong style="color:var(--text)">'+fmtRp(grandNilai)+'</strong>' : ''}
  </div>`;

  if (hasZeroPrice) {
    html += `<div style="background:#fff8e1;border:1px solid #ffe082;border-radius:6px;padding:9px 12px;margin-bottom:12px;font-size:12px;color:#7a5c00">
      ⚠ Beberapa item memiliki harga beli Rp 0 — pastikan harga sudah diisi sebelum import ke Jubelio.
    </div>`;
  }

  const rollWarnings = Object.values(productSummary).filter(p => p.totalQty > 0 && p.totalQty % p.roll !== 0);
  if (rollWarnings.length) {
    const items = rollWarnings.map(p => {
      const next = Math.ceil(p.totalQty / p.roll) * p.roll;
      return `<strong>${p.name}</strong>: ${p.totalQty} pcs (next: ${next}, roll ${p.roll})`;
    }).join('<br>');
    html += `<div style="background:#fce8e6;border:1px solid #f28b82;border-radius:6px;padding:9px 12px;margin-bottom:12px;font-size:12px;color:#7a0000">
      ⚠ Qty berikut bukan kelipatan 1 roll (60 pcs) — sesuaikan sebelum download:<br>${items}
    </div>`;
  }

  html += `<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">
    <thead><tr style="background:#f7f8fa;border-bottom:2px solid var(--g200)">
      <th style="padding:8px 10px;text-align:left;font-weight:600">Produk</th>
      ${sizes.map(s=>`<th style="padding:8px 10px;text-align:center;font-weight:600;min-width:40px">${s}</th>`).join('')}
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Total</th>
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Harga Beli</th>
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Est. Nilai</th>
    </tr></thead><tbody>`;

  for (const p of prods) {
    const uniquePrices = [...new Set(p.prices)];
    const priceStr = uniquePrices.length === 0 ? '—'
      : uniquePrices.length === 1 ? fmtRp(uniquePrices[0])
      : uniquePrices.map(pr=>fmtRp(pr)).join(' / ');
    const meta = [p.ip, p.collection].filter(Boolean).join(' · ');
    html += `<tr style="border-bottom:1px solid var(--g100)">
      <td style="padding:7px 10px">
        <div style="font-weight:500">${p.name} <span style="font-size:10px;color:var(--g400)">${p.brand}</span></div>
        ${meta ? `<div style="font-size:10px;color:var(--g400)">${meta}</div>` : ''}
      </td>
      ${sizes.map(s=>`<td style="padding:7px 10px;text-align:center;font-family:var(--mono);font-size:12px">${p.sizeQtys[s]??'—'}</td>`).join('')}
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-weight:600">${p.totalQty}</td>
      <td style="padding:7px 10px;text-align:right;font-size:11px;color:var(--g400)">${priceStr}</td>
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono)">${p.totalNilai>0?fmtRp(p.totalNilai):'—'}</td>
    </tr>`;
  }

  html += `<tr style="background:#f7f8fa;font-weight:700;border-top:2px solid var(--g200)">
    <td style="padding:8px 10px">Total</td>
    ${sizes.map(()=>`<td></td>`).join('')}
    <td style="padding:8px 10px;text-align:right;font-family:var(--mono)">${grandQty}</td>
    <td></td>
    <td style="padding:8px 10px;text-align:right;font-family:var(--mono)">${grandNilai>0?fmtRp(grandNilai):'—'}</td>
  </tr>`;

  html += `</tbody></table></div>`;

  const content = document.getElementById('rst-summary-content');
  if (content) content.innerHTML = html;
  const modal = document.getElementById('rst-summary-modal');
  if (modal) modal.style.display = 'flex';
}

function _rstCloseSummary() {
  const modal = document.getElementById('rst-summary-modal');
  if (modal) modal.style.display = 'none';
}

function _rstDoDownloadCSV() {
  _rstCloseSummary();

  const supplierEl   = document.getElementById('rst-supplier');
  const supplierName = supplierEl?.options[supplierEl.selectedIndex]?.text || 'MGMT';

  const items = [];
  document.querySelectorAll('.rst-var-chk:checked').forEach(chk => {
    const row   = chk.closest('tr');
    const qty   = parseFloat(row?.querySelector('.rst-qty-input')?.value)   || 0;
    const price = parseFloat(row?.querySelector('.rst-price-input')?.value) || 0;
    if (qty <= 0) return;
    items.push({ sku: chk.dataset.itemCode || '', qty, price });
  });

  if (!items.length) return;

  const note    = document.getElementById('rst-note')?.value || '';
  const today   = new Date().toISOString().slice(0, 10);
  const statusEl = document.getElementById('rst-gen-status');

  const esc = v => {
    const s = String(v ?? '');
    return (s.includes(',') || s.includes('"') || s.includes('\n'))
      ? '"' + s.replace(/"/g, '""') + '"' : s;
  };

  const COLS = ['No. Pesanan','No. Ref Pemasok','Tanggal','Zona Waktu','Nama Pemasok',
                'Email Pemasok','No Telp. Pemasok','Harga Termasuk Pajak','Lokasi',
                'Keterangan','SKU','Harga','Qty','Nilai Diskon','Pajak'];
  const lines = [COLS.join(',')];

  items.forEach((it, i) => {
    if (i === 0) {
      lines.push(['[auto]', '', esc(today), 'WIB', esc(supplierName),
        '', '0', 'FALSE', 'Gudang Penerimaan Barang',
        esc(note), esc(it.sku), it.price, it.qty, 0, 'No Tax'].join(','));
    } else {
      lines.push(['', '', '', '', '', '', '', '', '', '',
        esc(it.sku), it.price, it.qty, 0, 'No Tax'].join(','));
    }
  });

  const csv      = lines.join('\r\n');
  const blob     = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url      = URL.createObjectURL(blob);
  const filename = `PO-Restock-${today}.csv`;
  const a        = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);

  const totalQty = items.reduce((s,i) => s+i.qty, 0);
  if (statusEl) statusEl.innerHTML =
    `✅ <strong>${filename}</strong> berhasil diunduh · ${items.length} SKU · ${totalQty} unit`+
    ` · <span style="color:var(--g400);font-size:12px">Import via Jubelio → Pembelian → Import</span>`;
}

// ── MARTE SKU CATEGORIES ──
const MSC_CATS = ['Apparel','Accessories','Collectible','Wellness','Preloved','Others'];
let _mscAllRows  = [];    // raw rows from RPC
let _mscFiltered = [];    // rows after filter
let _mscPending  = {};    // {item_code: new_category} — unsaved changes

async function loadMarteSKUCat() {
  const wrap = document.getElementById('msc-brand-groups');
  const empty = document.getElementById('msc-empty');
  if (!wrap) return;
  wrap.innerHTML = '<div style="padding:40px;text-align:center;color:var(--g400)">Memuat data…</div>';
  empty.style.display = 'none';
  _mscPending = {};
  _mscUpdatePendingBadge();

  // Page the RPC response — PostgREST caps each response at 1000 rows.
  _mscAllRows = [];
  { const PAGE = 1000; let _from = 0;
    while (true) {
      const { data, error } = await sb.rpc('get_marte_sku_mapping').range(_from, _from + PAGE - 1);
      if (error) {
        wrap.innerHTML = `<div style="padding:40px;text-align:center;color:var(--red)">Error: ${error.message}</div>`;
        return;
      }
      _mscAllRows = _mscAllRows.concat(data || []);
      if (!data || data.length < PAGE) break;
      _from += PAGE;
    }
  }

  // Populate brand dropdown
  const brands = [...new Set(_mscAllRows.map(r => r.brand))].sort((a,b)=>a.localeCompare(b,'id'));
  const sel = document.getElementById('msc-filter-brand');
  const curVal = sel.value;
  sel.innerHTML = '<option value="">Semua Brand</option>';
  brands.forEach(b => {
    const o = document.createElement('option');
    o.value = b; o.textContent = b;
    if (b === curVal) o.selected = true;
    sel.appendChild(o);
  });

  _mscRenderStats();
  _mscApplyFilter();
}

function _mscRenderStats() {
  const el = document.getElementById('msc-stats');
  if (!el) return;
  const total = _mscAllRows.length;
  const uncat = _mscAllRows.filter(r => !r.fee_category).length;
  const catCount = total - uncat;
  const byBrand = {};
  _mscAllRows.forEach(r => {
    if (!byBrand[r.brand]) byBrand[r.brand] = {total:0,uncat:0};
    byBrand[r.brand].total++;
    if (!r.fee_category) byBrand[r.brand].uncat++;
  });
  const uncatBrands = Object.entries(byBrand).filter(([,v])=>v.uncat>0).length;

  el.innerHTML = `
    <div class="stat-card"><div class="sc-val">${total}</div><div class="sc-lbl">Total SKU</div></div>
    <div class="stat-card"><div class="sc-val" style="color:var(--green)">${catCount}</div><div class="sc-lbl">Terkategorikan</div></div>
    <div class="stat-card"><div class="sc-val" style="color:var(--amber,#f59e0b)">${uncat}</div><div class="sc-lbl">Belum Kategori</div></div>
    <div class="stat-card"><div class="sc-val" style="color:var(--amber,#f59e0b)">${uncatBrands}</div><div class="sc-lbl">Brand dgn gap</div></div>
  `;
}

function _mscApplyFilter() {
  const brand = document.getElementById('msc-filter-brand').value;
  const uncatOnly = document.getElementById('msc-filter-uncat').checked;
  _mscFiltered = _mscAllRows.filter(r => {
    if (brand && r.brand !== brand) return false;
    if (uncatOnly && r.fee_category) return false;
    return true;
  });
  _mscRenderGroups();
}

function _mscRenderGroups() {
  const wrap = document.getElementById('msc-brand-groups');
  const empty = document.getElementById('msc-empty');
  if (!wrap) return;

  if (_mscFiltered.length === 0) {
    wrap.innerHTML = '';
    empty.style.display = 'block';
    return;
  }
  empty.style.display = 'none';

  // Group by brand
  const groups = {};
  _mscFiltered.forEach(r => {
    if (!groups[r.brand]) groups[r.brand] = [];
    groups[r.brand].push(r);
  });

  let html = '';
  Object.keys(groups).sort((a,b)=>a.localeCompare(b,'id')).forEach(brand => {
    const rows = groups[brand];
    const uncatCount = rows.filter(r => !r.fee_category && !_mscPending[r.item_code]).length;
    const catOptions = MSC_CATS.map(c=>`<option value="${c}">${c}</option>`).join('');
    const safeB = brand.replace(/'/g,"\\'");

    html += `
      <div class="msc-brand-block" id="msc-block-${_mscSafeId(brand)}" style="margin-bottom:24px">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;padding:8px 10px;background:var(--g50,#f8f9fa);border-radius:8px;flex-wrap:wrap">
          <div style="font-family:var(--syne);font-weight:600;font-size:14px;flex:1;min-width:120px">${brand}</div>
          <div style="font-size:12px;color:var(--g400)">${rows.length} SKU${uncatCount>0?` · <span style="color:var(--amber,#f59e0b)">${uncatCount} belum</span>`:' · ✅ semua terkategori'}</div>
          <div style="display:flex;align-items:center;gap:6px">
            <span style="font-size:12px;color:var(--g500)">Set semua ke:</span>
            <select id="msc-bulk-${_mscSafeId(brand)}" style="padding:4px 8px;font-size:12px;border:1px solid var(--g200);border-radius:6px">
              <option value="">— Pilih —</option>
              ${catOptions}
            </select>
            <button onclick="_mscBulkApply('${safeB}', false)" title="Hanya terapkan ke item yang belum punya kategori" style="padding:4px 10px;font-size:12px;background:var(--g100);border:1px solid var(--g200);border-radius:6px;cursor:pointer">Yg Belum</button>
            <button onclick="_mscBulkApply('${safeB}', true)" title="Terapkan ke semua item brand ini" style="padding:4px 10px;font-size:12px;background:var(--primary);color:#fff;border:none;border-radius:6px;cursor:pointer">Semua</button>
          </div>
        </div>
        <table style="width:100%;border-collapse:collapse;font-size:13px">
          <thead>
            <tr style="border-bottom:2px solid var(--g100)">
              <th style="text-align:left;padding:6px 8px;color:var(--g400);font-weight:500;width:180px">Item Code</th>
              <th style="text-align:left;padding:6px 8px;color:var(--g400);font-weight:500">Nama Item</th>
              <th style="text-align:center;padding:6px 8px;color:var(--g400);font-weight:500;width:140px">Kategori Saat Ini</th>
              <th style="text-align:center;padding:6px 8px;color:var(--g400);font-weight:500;width:160px">Set Kategori</th>
            </tr>
          </thead>
          <tbody id="msc-tbody-${_mscSafeId(brand)}">
            ${rows.map(r => _mscItemRow(r)).join('')}
          </tbody>
        </table>
      </div>
    `;
  });
  wrap.innerHTML = html;
}

function _mscSafeId(brand) {
  return brand.replace(/[^a-zA-Z0-9]/g,'_');
}

function _mscItemRow(r) {
  const curCat = r.fee_category || '';
  const pending = _mscPending[r.item_code];
  const displayCat = pending !== undefined ? pending : curCat;
  const isChanged = pending !== undefined && pending !== curCat;

  const catPill = curCat
    ? `<span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;background:var(--g100);color:var(--g600)">${curCat}</span>`
    : `<span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;background:#fef3c7;color:#92400e">Belum</span>`;

  const catOpts = `<option value="">— Pilih —</option>`
    + MSC_CATS.map(c=>`<option value="${c}"${displayCat===c?' selected':''}>${c}</option>`).join('');

  const rowStyle = isChanged ? 'background:#fffbeb' : '';

  return `<tr style="border-bottom:1px solid var(--g50,#f8f9fa);${rowStyle}" id="msc-row-${r.item_code.replace(/[^a-zA-Z0-9]/g,'_')}">
    <td style="padding:6px 8px;font-family:var(--mono,monospace);font-size:11px;color:var(--g500)">${r.item_code}</td>
    <td style="padding:6px 8px">${r.item_name || '—'}</td>
    <td style="padding:6px 8px;text-align:center">${catPill}</td>
    <td style="padding:6px 8px;text-align:center">
      <select style="padding:4px 8px;font-size:12px;border:1px solid ${isChanged?'var(--amber,#f59e0b)':'var(--g200)'};border-radius:6px;width:140px"
              onchange="_mscSetPending('${r.item_code.replace(/'/g,"\\'")}', this.value)">${catOpts}</select>
    </td>
  </tr>`;
}

function _mscSetPending(itemCode, val) {
  const original = (_mscAllRows.find(r=>r.item_code===itemCode)||{}).fee_category || '';
  if (val === original) {
    delete _mscPending[itemCode];
  } else {
    _mscPending[itemCode] = val;
  }
  _mscUpdatePendingBadge();
  // highlight row
  const rowId = 'msc-row-'+itemCode.replace(/[^a-zA-Z0-9]/g,'_');
  const row = document.getElementById(rowId);
  if (row) {
    const isChanged = _mscPending[itemCode] !== undefined;
    row.style.background = isChanged ? '#fffbeb' : '';
    const sel = row.querySelector('select');
    if (sel) sel.style.borderColor = isChanged ? 'var(--amber,#f59e0b)' : 'var(--g200)';
  }
}

function _mscBulkApply(brand, applyAll) {
  const selEl = document.getElementById('msc-bulk-'+_mscSafeId(brand));
  if (!selEl || !selEl.value) { alert('Pilih kategori dulu.'); return; }
  const cat = selEl.value;
  const rows = _mscAllRows.filter(r => r.brand === brand);
  rows.forEach(r => {
    // "Unset" button (applyAll=false) → only apply to currently uncategorized
    // "Semua" button (applyAll=true) → apply to all items in brand
    if (applyAll || !r.fee_category) {
      const original = r.fee_category || '';
      if (cat === original) {
        delete _mscPending[r.item_code];
      } else {
        _mscPending[r.item_code] = cat;
      }
    }
  });
  _mscUpdatePendingBadge();
  _mscApplyFilter(); // re-render to show highlights
}

function _mscUpdatePendingBadge() {
  const count = Object.keys(_mscPending).length;
  const badge = document.getElementById('msc-pending-badge');
  const btn = document.getElementById('msc-save-btn');
  if (!badge || !btn) return;
  if (count > 0) {
    badge.style.display = 'inline-block';
    badge.textContent = `${count} perubahan pending`;
    btn.style.display = 'inline-block';
  } else {
    badge.style.display = 'none';
    btn.style.display = 'none';
  }
}

async function saveMarteSKUCat() {
  const pending = Object.entries(_mscPending);
  if (pending.length === 0) return;

  const btn = document.getElementById('msc-save-btn');
  if (btn) { btn.disabled = true; btn.textContent = 'Menyimpan…'; }

  // Only save rows that have a category (skip empty/cleared)
  const toUpsert = pending
    .filter(([,cat]) => cat !== '')
    .map(([item_code, fee_category]) => ({ item_code, fee_category }));

  // For cleared rows (set to ""), delete from marte_sku_categories
  const toDelete = pending.filter(([,cat]) => cat === '').map(([code]) => code);

  let errors = [];

  if (toUpsert.length > 0) {
    const { error } = await sb.from('marte_sku_categories')
      .upsert(toUpsert, { onConflict: 'item_code' });
    if (error) errors.push(error.message);
  }

  if (toDelete.length > 0) {
    const { error } = await sb.from('marte_sku_categories')
      .delete().in('item_code', toDelete);
    if (error) errors.push(error.message);
  }

  if (errors.length > 0) {
    alert('Ada error saat menyimpan:\n' + errors.join('\n'));
    if (btn) { btn.disabled = false; btn.textContent = '💾 Simpan Perubahan'; }
    return;
  }

  // Update local cache
  pending.forEach(([item_code, fee_category]) => {
    const row = _mscAllRows.find(r => r.item_code === item_code);
    if (row) row.fee_category = fee_category || null;
  });

  _mscPending = {};
  _mscUpdatePendingBadge();
  _mscRenderStats();
  _mscApplyFilter();

  if (btn) { btn.disabled = false; btn.textContent = '💾 Simpan Perubahan'; }

  // Brief success flash
  const badge = document.getElementById('msc-pending-badge');
  if (badge) {
    badge.style.display = 'inline-block';
    badge.style.background = 'var(--green)';
    badge.textContent = `✓ ${toUpsert.length + toDelete.length} SKU tersimpan`;
    setTimeout(() => { badge.style.display = 'none'; badge.style.background = ''; }, 3000);
  }

  await logActivity('marteskucat','bulk_update',null,`${toUpsert.length} categorized, ${toDelete.length} cleared`);
}

// Keep session in sync (handles token refresh, tab-switching, etc.)
sb.auth.onAuthStateChange((event, session) => {
  if (event === "SIGNED_OUT") {
    currentUser = ""; allRows = [];
    document.getElementById("app").style.display = "none";
    document.getElementById("loginScreen").style.display = "grid";
    const _cf = document.getElementById('chat-fab'); if (_cf) _cf.style.display='none';
    const _cp = document.getElementById('chat-popup'); if (_cp) _cp.style.display = 'none';
    _chatLoaded = false; _chatRealtime = null; _chatMsgs = [];
    document.getElementById("loginBox").style.display = "block";
    document.getElementById("resetBox").style.display = "none";
  }
});

// ── TEAM MEMBERS ──
let _teamRows = [];

async function loadTeamMembers(){
  const el = document.getElementById('team-list');
  if(!el) return;
  el.innerHTML = `<div style="color:var(--g400);font-size:13px;padding:20px">Memuat...</div>`;
  try{
    const { data, error } = await sb.from('team_members').select('*').order('name');
    if(error) throw error;
    _teamRows = data || [];
    renderTeamList();
  } catch(e){
    el.innerHTML = `<div style="color:#ef4444;font-size:13px;padding:20px">Gagal memuat: ${_esc(e.message)}</div>`;
  }
}

function renderTeamList(){
  const el = document.getElementById('team-list');
  if(!el) return;
  if(!_teamRows.length){
    el.innerHTML = `<div style="color:var(--g400);font-size:13px;padding:20px;font-style:italic">Belum ada anggota tim. Klik "+ Tambah Anggota" untuk mulai.</div>`;
    return;
  }
  el.innerHTML = _teamRows.map(m => {
    const initials = (m.name||'?').split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2);
    return `
    <div style="background:var(--white);border:1px solid var(--g100);border-radius:12px;padding:16px 18px;display:flex;flex-direction:column;gap:10px;transition:box-shadow .15s;${m.is_active?'':'opacity:.55'}"
      onmouseover="this.style.boxShadow='0 2px 10px rgba(0,0,0,.07)'" onmouseout="this.style.boxShadow=''">
      <div style="display:flex;align-items:center;gap:12px">
        <div style="width:42px;height:42px;border-radius:50%;background:${_teamAvatarColor(m.name)};display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:#fff;flex-shrink:0;letter-spacing:.5px">
          ${initials}
        </div>
        <div style="flex:1;min-width:0">
          <div style="font-size:14px;font-weight:600;color:var(--black);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${_esc(m.name)}${m.is_admin?' <span class="pill p-signings" style="font-size:9px;vertical-align:middle">ADMIN</span>':''}</div>
          <div style="font-size:11px;color:var(--g400);margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${m.role ? _esc(m.role) : '<span style="font-style:italic;color:var(--g300)">No role</span>'}</div>
        </div>
      </div>
      ${m.email ? `<div style="font-size:11px;color:var(--g400);font-family:var(--mono);background:var(--off);border-radius:6px;padding:5px 8px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${_esc(m.email)}</div>` : ''}
      <div style="font-size:11px;color:var(--g400)">Akses: <strong style="color:var(--g600)">${m.is_admin?'Semua (admin)':(Array.isArray(m.module_access)?m.module_access.length+' modul':'Semua')}</strong></div>
      ${_isAdmin?`<button onclick="openTeamAccess('${_esc(m.id)}')" style="padding:5px 10px;border-radius:6px;border:1px solid #c7d2fe;background:#eef2ff;color:#4f46e5;font-size:12px;cursor:pointer;text-align:center">🔑 Atur Akses</button>`:''}
      <div style="display:flex;align-items:center;gap:6px;padding-top:2px;border-top:1px solid var(--g100)">
        <button onclick="openEditTeamMember('${_esc(m.id)}')"
          style="flex:1;padding:5px 10px;border-radius:6px;border:1px solid var(--g200);background:none;color:var(--g600);font-size:12px;cursor:pointer;text-align:center"
          onmouseover="this.style.background='var(--off)'" onmouseout="this.style.background='none'">✏ Edit</button>
        <button onclick="toggleTeamActive('${_esc(m.id)}',${!m.is_active})"
          style="flex:1;padding:5px 10px;border-radius:6px;border:1px solid ${m.is_active?'var(--g200)':'#fca5a5'};background:${m.is_active?'none':'#fff1f2'};color:${m.is_active?'var(--g600)':'#ef4444'};font-size:12px;cursor:pointer;text-align:center"
          onmouseover="this.style.background='var(--off)'" onmouseout="this.style.background='${m.is_active?'none':'#fff1f2'}'">
          ${m.is_active?'✓ Aktif':'✕ Nonaktif'}</button>
        <button onclick="deleteTeamMember('${_esc(m.id)}')"
          style="padding:5px 9px;border-radius:6px;border:1px solid var(--g100);background:none;color:var(--g400);font-size:13px;cursor:pointer"
          onmouseover="this.style.color='#ef4444';this.style.borderColor='#fca5a5'" onmouseout="this.style.color='var(--g400)';this.style.borderColor='var(--g100)'">🗑</button>
      </div>
    </div>`;
  }).join('');
}

function _teamAvatarColor(name){
  const colors = ['#6366f1','#3b82f6','#10b981','#f59e0b','#ef4444','#8b5cf6','#ec4899','#14b8a6'];
  let h = 0; for(let i=0;i<(name||'').length;i++) h = name.charCodeAt(i) + ((h<<5)-h);
  return colors[Math.abs(h) % colors.length];
}

function openAddTeamMember(){
  const modal = document.createElement('div');
  modal.style.cssText = 'position:fixed;inset:0;z-index:600;background:rgba(0,0,0,0.45);display:flex;align-items:center;justify-content:center';
  modal.onclick = e => { if(e.target===modal) modal.remove(); };
  modal.innerHTML = `
    <div style="background:var(--white);border-radius:14px;padding:28px;width:360px;box-shadow:0 8px 32px rgba(0,0,0,.15)">
      <div style="font-family:var(--head);font-size:16px;font-weight:700;margin-bottom:18px">Tambah Anggota Tim</div>
      <div style="display:flex;flex-direction:column;gap:10px">
        <div>
          <div class="fg-label">Nama <span style="color:#ef4444">*</span></div>
          <input id="tm-name" type="text" placeholder="Nama lengkap…"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
        <div>
          <div class="fg-label">Role / Jabatan</div>
          <input id="tm-role" type="text" placeholder="mis. Designer, PM, Sales…"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
        <div>
          <div class="fg-label">Email</div>
          <input id="tm-email" type="email" placeholder="nama@sentra.com"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
      </div>
      <div style="display:flex;gap:8px;margin-top:20px;justify-content:flex-end">
        <button onclick="this.closest('[style*=fixed]').remove()"
          style="padding:8px 16px;background:none;border:1px solid var(--g200);border-radius:8px;font-size:13px;cursor:pointer">Batal</button>
        <button onclick="saveNewTeamMember(this)"
          style="padding:8px 18px;background:var(--black);color:var(--white);border:none;border-radius:8px;font-size:13px;cursor:pointer">Simpan</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.querySelector('#tm-name').focus();
  modal.querySelector('#tm-name').onkeydown = e => { if(e.key==='Enter') modal.querySelector('[onclick*=saveNewTeamMember]').click(); };
}

async function saveNewTeamMember(btn){
  const modal = btn.closest('[style*=fixed]');
  const name = modal.querySelector('#tm-name').value.trim();
  if(!name){ modal.querySelector('#tm-name').style.borderColor='#ef4444'; return; }
  const role  = modal.querySelector('#tm-role').value.trim() || null;
  const email = modal.querySelector('#tm-email').value.trim() || null;
  btn.disabled = true; btn.textContent = 'Menyimpan…';
  try{
    const { data, error } = await sb.from('team_members').insert({ name, role, email }).select().single();
    if(error) throw error;
    _teamRows.push(data);
    // Update _teamPics + acPics live so autocomplete works immediately
    if(!_teamPics.includes(data.name)) _teamPics.push(data.name);
    if(!acPics.includes(data.name)) acPics.push(data.name);
    renderTeamList();
    modal.remove();
  } catch(e){
    btn.disabled=false; btn.textContent='Simpan';
    alert('Gagal menyimpan: '+e.message);
  }
}

function openEditTeamMember(id){
  const m = _teamRows.find(x=>x.id===id);
  if(!m) return;
  const modal = document.createElement('div');
  modal.style.cssText = 'position:fixed;inset:0;z-index:600;background:rgba(0,0,0,0.45);display:flex;align-items:center;justify-content:center';
  modal.onclick = e => { if(e.target===modal) modal.remove(); };
  modal.innerHTML = `
    <div style="background:var(--white);border-radius:14px;padding:28px;width:360px;box-shadow:0 8px 32px rgba(0,0,0,.15)">
      <div style="font-family:var(--head);font-size:16px;font-weight:700;margin-bottom:18px">Edit Anggota Tim</div>
      <div style="display:flex;flex-direction:column;gap:10px">
        <div>
          <div class="fg-label">Nama <span style="color:#ef4444">*</span></div>
          <input id="tm-edit-name" type="text" value="${_esc(m.name)}"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
        <div>
          <div class="fg-label">Role / Jabatan</div>
          <input id="tm-edit-role" type="text" value="${_esc(m.role||'')}" placeholder="mis. Designer, PM, Sales…"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
        <div>
          <div class="fg-label">Email</div>
          <input id="tm-edit-email" type="email" value="${_esc(m.email||'')}" placeholder="nama@sentra.com"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
      </div>
      <div style="display:flex;gap:8px;margin-top:20px;justify-content:flex-end">
        <button onclick="this.closest('[style*=fixed]').remove()"
          style="padding:8px 16px;background:none;border:1px solid var(--g200);border-radius:8px;font-size:13px;cursor:pointer">Batal</button>
        <button onclick="saveEditTeamMember('${_esc(id)}',this)"
          style="padding:8px 18px;background:var(--black);color:var(--white);border:none;border-radius:8px;font-size:13px;cursor:pointer">Simpan</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.querySelector('#tm-edit-name').focus();
}

async function saveEditTeamMember(id, btn){
  const modal = btn.closest('[style*=fixed]');
  const name  = modal.querySelector('#tm-edit-name').value.trim();
  if(!name){ modal.querySelector('#tm-edit-name').style.borderColor='#ef4444'; return; }
  const role  = modal.querySelector('#tm-edit-role').value.trim() || null;
  const email = modal.querySelector('#tm-edit-email').value.trim() || null;
  btn.disabled = true; btn.textContent = 'Menyimpan…';
  try{
    const { error } = await sb.from('team_members').update({ name, role, email }).eq('id', id);
    if(error) throw error;
    const m = _teamRows.find(x=>x.id===id);
    if(m){
      // Update _teamPics/acPics if name changed
      if(m.name !== name){
        const oldName = m.name;
        _teamPics = _teamPics.map(n => n===oldName ? name : n);
        acPics    = acPics.map(n => n===oldName ? name : n);
      }
      m.name = name; m.role = role; m.email = email;
    }
    renderTeamList();
    modal.remove();
  } catch(e){
    btn.disabled=false; btn.textContent='Simpan';
    alert('Gagal menyimpan: '+e.message);
  }
}

// ── Access management (admin only) ──
function openTeamAccess(id){
  if(!_isAdmin) return;
  const m=_teamRows.find(x=>x.id===id); if(!m) return;
  const cur = Array.isArray(m.module_access) ? new Set(m.module_access) : null; // null = all
  const allChecked = cur===null;
  const modal=document.createElement('div');
  modal.style.cssText='position:fixed;inset:0;z-index:600;background:rgba(0,0,0,0.45);display:flex;align-items:center;justify-content:center;padding:20px';
  modal.onclick=e=>{ if(e.target===modal) modal.remove(); };
  const checks=ACCESS_MODULES.map(mod=>`
    <label style="display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:6px;font-size:12px;cursor:pointer"
      onmouseover="this.style.background='var(--off)'" onmouseout="this.style.background=''">
      <input type="checkbox" class="tac-mod" value="${mod.key}" ${allChecked||cur.has(mod.key)?'checked':''}> ${_esc(mod.label)}
    </label>`).join('');
  modal.innerHTML=`
    <div style="background:var(--white);border-radius:14px;padding:24px;width:520px;max-height:88vh;display:flex;flex-direction:column;box-shadow:0 8px 32px rgba(0,0,0,.15)">
      <div style="font-family:var(--head);font-size:16px;font-weight:700;margin-bottom:4px">Atur Akses — ${_esc(m.name)}</div>
      <div style="font-size:12px;color:var(--g400);margin-bottom:14px">Centang modul yang boleh diakses. Centang semua = akses penuh.</div>
      <label style="display:flex;align-items:center;gap:8px;font-size:13px;font-weight:600;margin-bottom:10px;padding:8px;background:#eef2ff;border-radius:8px;cursor:pointer">
        <input type="checkbox" id="tac-admin" ${m.is_admin?'checked':''}> 👑 Admin (akses semua + bisa atur akses orang lain)
      </label>
      <div style="display:flex;gap:8px;margin-bottom:8px">
        <button onclick="document.querySelectorAll('.tac-mod').forEach(c=>c.checked=true)" style="font-size:11px;padding:4px 10px;border:1px solid var(--g200);border-radius:6px;background:none;cursor:pointer">Centang semua</button>
        <button onclick="document.querySelectorAll('.tac-mod').forEach(c=>c.checked=false)" style="font-size:11px;padding:4px 10px;border:1px solid var(--g200);border-radius:6px;background:none;cursor:pointer">Kosongkan</button>
      </div>
      <div style="flex:1;overflow-y:auto;border:1px solid var(--g100);border-radius:8px;padding:6px;display:grid;grid-template-columns:1fr 1fr;gap:2px">${checks}</div>
      <div style="display:flex;gap:8px;margin-top:16px;justify-content:flex-end">
        <button onclick="this.closest('[style*=fixed]').remove()" style="padding:8px 16px;background:none;border:1px solid var(--g200);border-radius:8px;font-size:13px;cursor:pointer">Batal</button>
        <button onclick="saveTeamAccess('${_esc(id)}',this)" style="padding:8px 18px;background:var(--black);color:var(--white);border:none;border-radius:8px;font-size:13px;cursor:pointer">Simpan</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
}

async function saveTeamAccess(id, btn){
  const modal=btn.closest('[style*=fixed]');
  const isAdmin=modal.querySelector('#tac-admin').checked;
  const checked=[...modal.querySelectorAll('.tac-mod:checked')].map(c=>c.value);
  // all checked → null (full access); else the array
  const moduleAccess = (checked.length===ACCESS_MODULES.length) ? null : checked;
  btn.disabled=true; btn.textContent='Menyimpan…';
  try{
    const {error}=await sb.from('team_members').update({is_admin:isAdmin, module_access:moduleAccess}).eq('id',id);
    if(error) throw error;
    const m=_teamRows.find(x=>x.id===id);
    if(m){ m.is_admin=isAdmin; m.module_access=moduleAccess; }
    renderTeamList();
    modal.remove();
  }catch(e){ btn.disabled=false; btn.textContent='Simpan'; alert('Gagal: '+e.message); }
}

async function toggleTeamActive(id, newState){
  try{
    await sb.from('team_members').update({is_active:newState}).eq('id',id);
    const m = _teamRows.find(x=>x.id===id);
    if(m) m.is_active = newState;
    // Sync _teamPics and acPics
    _teamPics = _teamRows.filter(x=>x.is_active).map(x=>x.name);
    acPics = [...new Set([..._teamPics, ...acPics.filter(n=>!_teamRows.map(x=>x.name).includes(n))])];
    renderTeamList();
  } catch(e){ alert('Gagal: '+e.message); }
}

async function deleteTeamMember(id){
  if(!confirm('Hapus anggota ini dari daftar tim?')) return;
  try{
    await sb.from('team_members').delete().eq('id',id);
    _teamRows = _teamRows.filter(x=>x.id!==id);
    _teamPics = _teamRows.filter(x=>x.is_active).map(x=>x.name);
    acPics = [...new Set([..._teamPics, ...acPics.filter(n=>!_teamRows.map(x=>x.name).includes(n))])];
    renderTeamList();
  } catch(e){ alert('Gagal hapus: '+e.message); }
}

